+codeunit 134998 "Reminder Level Communication Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        Assert: Codeunit Assert;
+
+    [Test]
+    [HandlerFunctions('LanguagesModalPageHandler,ConfirmHandlerNo')]
+    [Scope('OnPrem')]
+    procedure AddTextForLanguageWhenNoAttachmentTextsExist()
+    var
+        ReminderTerms: Record "Reminder Terms";
+        ReminderLevel: Record "Reminder Level";
+        ReminderAttachmentText: Record "Reminder Attachment Text";
+        ReminderLevelCommunicationPage: TestPage "Reminder Level Communication";
+        LanguageCode: Code[10];
+    begin
+        // [SCENARIO 539690] Error "A reminder attachment text cannot be created without an ID" when adding text for language in Reminder Level Communication
+        // when no attachment texts exist
+
+        // [GIVEN] Create reminder terms and a reminder level without any attachment texts
+        LibraryERM.CreateReminderTerms(ReminderTerms);
+        LibraryERM.CreateReminderLevel(ReminderLevel, ReminderTerms.Code);
+
+        // [GIVEN] Verify that the Reminder Attachment Text ID is empty (null GUID)
+        Assert.IsTrue(IsNullGuid(ReminderLevel."Reminder Attachment Text"), 'Expected Reminder Attachment Text to be empty GUID initially.');
+
+        // [GIVEN] Get a language code to use for testing
+        LanguageCode := LibraryERM.GetAnyLanguageDifferentFromCurrent();
+        LibraryVariableStorage.Enqueue(LanguageCode);
+
+        // [WHEN] Open the Reminder Level Communication page and add text for language
+        // The page will prompt for default creation of attachment/email texts - we say No to both
+        // Then we invoke "Add New Language" action
+        ReminderLevelCommunicationPage.OpenEdit();
+        ReminderLevelCommunicationPage.GoToRecord(ReminderLevel);
+        ReminderLevelCommunicationPage."Add New Language".Invoke();
+        ReminderLevelCommunicationPage.Close();
+
+        // [THEN] No error occurs and the reminder attachment text is created
+        ReminderLevel.Get(ReminderTerms.Code, ReminderLevel."No.");
+        Assert.IsFalse(IsNullGuid(ReminderLevel."Reminder Attachment Text"), 'Expected Reminder Attachment Text ID to be assigned.');
+
+        // [THEN] Verify that a Reminder Attachment Text record exists with the correct language code
+        ReminderAttachmentText.SetRange(Id, ReminderLevel."Reminder Attachment Text");
+        ReminderAttachmentText.SetRange("Language Code", LanguageCode);
+        Assert.IsTrue(ReminderAttachmentText.FindFirst(), 'Expected Reminder Attachment Text record to exist for the selected language.');
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure LanguagesModalPageHandler(var LanguagesPage: TestPage Languages)
+    var
+        LanguageCode: Code[10];
+    begin
+        LanguageCode := CopyStr(LibraryVariableStorage.DequeueText(), 1, MaxStrLen(LanguageCode));
+        LanguagesPage.Filter.SetFilter(Code, LanguageCode);
+        LanguagesPage.First();
+        LanguagesPage.OK().Invoke();
+    end;
+
+    [ConfirmHandler]
+    [Scope('OnPrem')]
+    procedure ConfirmHandlerNo(Question: Text[1024]; var Reply: Boolean)
+    begin
+        // Reply No to the confirmation dialogs for creating default attachment/email texts
+        Reply := false;
+    end;
+}

diff --git a/App/Apps/W1/Shopify/test/Invoicing/ShpfyCopyDocumentTest.Codeunit.al b/App/Apps/W1/Shopify/test/Invoicing/ShpfyCopyDocumentTest.Codeunit.al
