@@ -0,0 +1,90 @@
+codeunit 139614 "Shpfy Copy Document Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryAssert: Codeunit "Library Assert";
+        IsInitialized: Boolean;
+
+    local procedure Initialize()
+    begin
+        if IsInitialized then
+            exit;
+        LibraryRandom.Init();
+        IsInitialized := true;
+    end;
+
+    [Test]
+    procedure CopyFromPostedInvoiceClearsShopifyOrderId()
+    var
+        SalesHeader: Record "Sales Header";
+        SalesInvoiceHeader: Record "Sales Invoice Header";
+        CopyDocumentMgt: Codeunit "Copy Document Mgt.";
+        ShopifyOrderId: BigInteger;
+        ShopifyOrderNo: Code[50];
+        ShopifyRefundId: BigInteger;
+        PostedInvoiceNo: Code[20];
+    begin
+        // [SCENARIO] When copying a posted sales invoice that has Shopify Order fields populated,
+        // the new sales document should have these fields cleared.
+        Initialize();
+
+        // [GIVEN] A posted sales invoice with Shopify Order Id, Order No., and Refund Id populated
+        ShopifyOrderId := LibraryRandom.RandIntInRange(100000, 999999);
+        ShopifyOrderNo := CopyStr(LibraryRandom.RandText(20), 1, MaxStrLen(ShopifyOrderNo));
+        ShopifyRefundId := LibraryRandom.RandIntInRange(100000, 999999);
+        PostedInvoiceNo := CreatePostedSalesInvoiceWithShopifyFields(ShopifyOrderId, ShopifyOrderNo, ShopifyRefundId);
+
+        // Verify the posted invoice has the Shopify fields set
+        SalesInvoiceHeader.Get(PostedInvoiceNo);
+        LibraryAssert.AreEqual(ShopifyOrderId, SalesInvoiceHeader."Shpfy Order Id", 'Posted invoice should have Shopify Order Id');
+        LibraryAssert.AreEqual(ShopifyOrderNo, SalesInvoiceHeader."Shpfy Order No.", 'Posted invoice should have Shopify Order No.');
+        LibraryAssert.AreEqual(ShopifyRefundId, SalesInvoiceHeader."Shpfy Refund Id", 'Posted invoice should have Shopify Refund Id');
+
+        // [GIVEN] A new sales invoice to copy into
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, SalesInvoiceHeader."Sell-to Customer No.");
+
+        // [WHEN] Copy Document is executed with IncludeHeader = true
+        CopyDocumentMgt.SetProperties(true, false, false, false, true, false, false);
+        CopyDocumentMgt.CopySalesDoc("Sales Document Type From"::"Posted Invoice", PostedInvoiceNo, SalesHeader);
+
+        // [THEN] The Shopify Order Id should be cleared
+        LibraryAssert.AreEqual(0, SalesHeader."Shpfy Order Id", 'Shopify Order Id should be cleared after copy');
+
+        // [THEN] The Shopify Order No. should be cleared
+        LibraryAssert.AreEqual('', SalesHeader."Shpfy Order No.", 'Shopify Order No. should be cleared after copy');
+
+        // [THEN] The Shopify Refund Id should be cleared
+        LibraryAssert.AreEqual(0, SalesHeader."Shpfy Refund Id", 'Shopify Refund Id should be cleared after copy');
+    end;
+
+    local procedure CreatePostedSalesInvoiceWithShopifyFields(ShopifyOrderId: BigInteger; ShopifyOrderNo: Code[50]; ShopifyRefundId: BigInteger): Code[20]
+    var
+        Customer: Record Customer;
+        SalesHeader: Record "Sales Header";
+        SalesInvoiceHeader: Record "Sales Invoice Header";
+        PostedInvoiceNo: Code[20];
+    begin
+        LibrarySales.CreateCustomer(Customer);
+        LibrarySales.CreateSalesInvoice(SalesHeader);
+        SalesHeader.Validate("Sell-to Customer No.", Customer."No.");
+        SalesHeader."Shpfy Order Id" := ShopifyOrderId;
+        SalesHeader."Shpfy Order No." := ShopifyOrderNo;
+        SalesHeader."Shpfy Refund Id" := ShopifyRefundId;
+        SalesHeader.Modify(true);
+
+        PostedInvoiceNo := LibrarySales.PostSalesDocument(SalesHeader, false, true);
+
+        // Update the posted invoice with Shopify fields since they may not transfer
+        SalesInvoiceHeader.Get(PostedInvoiceNo);
+        SalesInvoiceHeader."Shpfy Order Id" := ShopifyOrderId;
+        SalesInvoiceHeader."Shpfy Order No." := ShopifyOrderNo;
+        SalesInvoiceHeader."Shpfy Refund Id" := ShopifyRefundId;
+        SalesInvoiceHeader.Modify();
+
+        exit(PostedInvoiceNo);
+    end;
+}

diff --git a/App/Layers/W1/Tests/ERM/ERMRecurringJnlUnlinkIncDoc.Codeunit.al b/App/Layers/W1/Tests/ERM/ERMRecurringJnlUnlinkIncDoc.Codeunit.al
