+codeunit 134230 "ERM Recurring Jnl Unlink IncDoc"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Recurring Journal] [Incoming Document]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryIncomingDocuments: Codeunit "Library - Incoming Documents";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PostRecurringJournalWithUnlinkIncDocOnPosting()
+    var
+        GenJournalTemplate: Record "Gen. Journal Template";
+        GenJournalBatch: Record "Gen. Journal Batch";
+        GenJournalLine: Record "Gen. Journal Line";
+        GenJnlAllocation: Record "Gen. Jnl. Allocation";
+        IncomingDocument: Record "Incoming Document";
+        GLAccount: Record "G/L Account";
+        RecurringFrequency: DateFormula;
+        DocumentNo: Code[20];
+        Amount: Decimal;
+    begin
+        // [SCENARIO] Posting Recurring General Journal with "Unlink Inc. Doc On Posting" option enabled should succeed without errors
+        // [GIVEN] A recurring general journal template with "Unlink Inc. Doc On Posting" = true
+        Initialize();
+
+        // Create recurring template with Unlink Inc. Doc On Posting enabled
+        LibraryERM.CreateRecurringTemplateName(GenJournalTemplate);
+        GenJournalTemplate.Validate("Unlink Inc. Doc On Posting", true);
+        GenJournalTemplate.Modify(true);
+
+        // Create batch for the template
+        LibraryERM.CreateRecurringBatchName(GenJournalBatch, GenJournalTemplate.Name);
+
+        // Create G/L Account without VAT for simpler posting
+        GLAccount.SetRange("VAT Prod. Posting Group", '');
+        LibraryERM.FindDirectPostingGLAccount(GLAccount);
+
+        // [GIVEN] A recurring journal line with an attached incoming document
+        DocumentNo := LibraryUtility.GenerateGUID();
+        Amount := LibraryRandom.RandDec(100, 2);
+        Evaluate(RecurringFrequency, '<1M>');
+
+        LibraryERM.CreateGeneralJnlLine(
+            GenJournalLine,
+            GenJournalBatch."Journal Template Name",
+            GenJournalBatch.Name,
+            GenJournalLine."Document Type"::" ",
+            GenJournalLine."Account Type"::"G/L Account",
+            GLAccount."No.",
+            Amount);
+        GenJournalLine.Validate("Document No.", DocumentNo);
+        GenJournalLine.Validate("Recurring Method", GenJournalLine."Recurring Method"::"F  Fixed");
+        GenJournalLine.Validate("Recurring Frequency", RecurringFrequency);
+        GenJournalLine.Modify(true);
+
+        // Create allocation line for the recurring journal line
+        LibraryERM.CreateGenJnlAllocation(
+            GenJnlAllocation,
+            GenJournalLine."Journal Template Name",
+            GenJournalLine."Journal Batch Name",
+            GenJournalLine."Line No.");
+        GenJnlAllocation.Validate("Account No.", LibraryERM.CreateGLAccountNo());
+        GenJnlAllocation.Validate("Allocation %", 100);
+        GenJnlAllocation.Modify(true);
+
+        // Create and attach incoming document to the journal line
+        LibraryIncomingDocuments.CreateNewIncomingDocument(IncomingDocument);
+        GenJournalLine.Validate("Incoming Document Entry No.", IncomingDocument."Entry No.");
+        GenJournalLine.Modify(true);
+
+        // [WHEN] Posting the recurring general journal
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
+
+        // [THEN] The posting succeeds without error "The changes to the Gen. Journal Line record cannot be saved because some information is not up-to-date"
+        // [THEN] The incoming document entry no. on the recurring journal line is reset to 0
+        GenJournalLine.Get(GenJournalLine."Journal Template Name", GenJournalLine."Journal Batch Name", GenJournalLine."Line No.");
+        Assert.AreEqual(0, GenJournalLine."Incoming Document Entry No.", 'Incoming Document Entry No. should be unlinked after posting.');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PostRecurringJournalMultipleLinesWithUnlinkIncDocOnPosting()
+    var
+        GenJournalTemplate: Record "Gen. Journal Template";
+        GenJournalBatch: Record "Gen. Journal Batch";
+        GenJournalLine: array[3] of Record "Gen. Journal Line";
+        GenJnlAllocation: Record "Gen. Jnl. Allocation";
+        IncomingDocument: array[3] of Record "Incoming Document";
+        GLAccount: Record "G/L Account";
+        GLEntry: Record "G/L Entry";
+        RecurringFrequency: DateFormula;
+        DocumentNo: Code[20];
+        Amount: Decimal;
+        i: Integer;
+    begin
+        // [SCENARIO] Posting Recurring General Journal with multiple lines and "Unlink Inc. Doc On Posting" option enabled should succeed
+        // [GIVEN] A recurring general journal template with "Unlink Inc. Doc On Posting" = true
+        Initialize();
+
+        // Create recurring template with Unlink Inc. Doc On Posting enabled
+        LibraryERM.CreateRecurringTemplateName(GenJournalTemplate);
+        GenJournalTemplate.Validate("Unlink Inc. Doc On Posting", true);
+        GenJournalTemplate.Modify(true);
+
+        // Create batch for the template
+        LibraryERM.CreateRecurringBatchName(GenJournalBatch, GenJournalTemplate.Name);
+
+        // Create G/L Account without VAT for simpler posting
+        GLAccount.SetRange("VAT Prod. Posting Group", '');
+        LibraryERM.FindDirectPostingGLAccount(GLAccount);
+
+        DocumentNo := LibraryUtility.GenerateGUID();
+        Evaluate(RecurringFrequency, '<1M>');
+
+        // [GIVEN] Three recurring journal lines with attached incoming documents
+        for i := 1 to 3 do begin
+            Amount := LibraryRandom.RandDec(100, 2);
+
+            LibraryERM.CreateGeneralJnlLine(
+                GenJournalLine[i],
+                GenJournalBatch."Journal Template Name",
+                GenJournalBatch.Name,
+                GenJournalLine[i]."Document Type"::" ",
+                GenJournalLine[i]."Account Type"::"G/L Account",
+                GLAccount."No.",
+                Amount);
+            GenJournalLine[i].Validate("Document No.", DocumentNo);
+            GenJournalLine[i].Validate("Recurring Method", GenJournalLine[i]."Recurring Method"::"F  Fixed");
+            GenJournalLine[i].Validate("Recurring Frequency", RecurringFrequency);
+            GenJournalLine[i].Modify(true);
+
+            // Create allocation line for each recurring journal line
+            LibraryERM.CreateGenJnlAllocation(
+                GenJnlAllocation,
+                GenJournalLine[i]."Journal Template Name",
+                GenJournalLine[i]."Journal Batch Name",
+                GenJournalLine[i]."Line No.");
+            GenJnlAllocation.Validate("Account No.", LibraryERM.CreateGLAccountNo());
+            GenJnlAllocation.Validate("Allocation %", 100);
+            GenJnlAllocation.Modify(true);
+
+            // Create and attach incoming document
+            LibraryIncomingDocuments.CreateNewIncomingDocument(IncomingDocument[i]);
+            GenJournalLine[i].Validate("Incoming Document Entry No.", IncomingDocument[i]."Entry No.");
+            GenJournalLine[i].Modify(true);
+        end;
+
+        // [WHEN] Posting the recurring general journal
+        GenJournalLine[1].SetRange("Journal Template Name", GenJournalBatch."Journal Template Name");
+        GenJournalLine[1].SetRange("Journal Batch Name", GenJournalBatch.Name);
+        GenJournalLine[1].FindFirst();
+        LibraryERM.PostGeneralJnlLine(GenJournalLine[1]);
+
+        // [THEN] The posting succeeds without error
+        // [THEN] G/L Entries are created
+        GLEntry.SetRange("Journal Batch Name", GenJournalBatch.Name);
+        Assert.RecordIsNotEmpty(GLEntry);
+
+        // [THEN] All incoming document entry numbers on the recurring journal lines are reset to 0
+        for i := 1 to 3 do begin
+            GenJournalLine[i].Get(GenJournalLine[i]."Journal Template Name", GenJournalLine[i]."Journal Batch Name", GenJournalLine[i]."Line No.");
+            Assert.AreEqual(0, GenJournalLine[i]."Incoming Document Entry No.", StrSubstNo('Incoming Document Entry No. should be unlinked after posting for line %1.', i));
+        end;
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"ERM Recurring Jnl Unlink IncDoc");
+
+        if IsInitialized then
+            exit;
+
+        IsInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"ERM Recurring Jnl Unlink IncDoc");
+    end;
+}

diff --git a/App/Layers/W1/Tests/VAT/NonDedVATMisc.Codeunit.al b/App/Layers/W1/Tests/VAT/NonDedVATMisc.Codeunit.al
