+++ b/App/Layers/W1/Tests/VAT/NonDedVATMisc.Codeunit.al
@@ -921,6 +921,64 @@ codeunit 134284 "Non Ded. VAT Misc."
             'Total Cost (LCY) with Non-Deductible VAT amount is not correct in Job Journal Line');
     end;

+    [Test]
+    [Scope('OnPrem')]
+    procedure JobJnlLineWithNonDeductNormalVATFromGenJnlLineFCYJob()
+    var
+        VATPostingSetup: Record "VAT Posting Setup";
+        GenJnlLine: Record "Gen. Journal Line";
+        JobJnlLine: Record "Job Journal Line";
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        Customer: Record Customer;
+        JobTransferLine: Codeunit "Job Transfer Line";
+        DeductiblePercent: Decimal;
+        CurrencyFactor: Decimal;
+        ExpectedNonDedVATAmountLCY: Decimal;
+        ExpectedUnitCostLCY: Decimal;
+        ExpectedTotalCostLCY: Decimal;
+    begin
+        // [FEATURE] [Normal VAT] [FCY] [UT]
+        // [SCENARIO] Non-Deductible VAT is correctly added to job journal line unit cost when project has foreign currency
+        // The issue: when general journal line is in LCY and project is in FCY (e.g., EUR),
+        // the Non-Deductible VAT amount was incorrectly added without proper currency conversion.
+        Initialize();
+        LibraryNonDeductibleVAT.SetUseForJobCost();
+
+        // [GIVEN] VAT Posting Setup, where "Tax Calculation Type"::"Normal VAT", 'Deductible %' is '60'
+        DeductiblePercent := LibraryRandom.RandInt(90);
+        CreateNonDeductibleVATPostingSetup(VATPostingSetup, "Tax Calculation Type"::"Normal VAT", '', DeductiblePercent);
+
+        // [GIVEN] Job 'J' with Currency Code = EUR (foreign currency)
+        LibrarySales.CreateCustomer(Customer);
+        LibraryJob.CreateJob(Job, Customer."No.");
+        Job.Validate("Currency Code", LibraryERM.CreateCurrencyWithRandomExchRates());
+        Job.Modify(true);
+        LibraryJob.CreateJobTask(Job, JobTask);
+
+        // [GIVEN] General journal line in LCY (blank currency) with Amount = 100, "Job No." = 'J', "Job Task No." = 'JT', "Job Line Type" = 'Billable'
+        CreateJobGLJournalLineWithFCYJob(GenJnlLine, VATPostingSetup, JobTask);
+
+        // [WHEN] Run FromGenJnlLineToJnlLine
+        JobTransferLine.FromGenJnlLineToJnlLine(GenJnlLine, JobJnlLine);
+
+        // [THEN] Non-Deductible VAT amount in JobJnlLine is correctly converted using job currency factor
+        // Currency factor is used to convert the Non-Deductible VAT amount for the job currency context
+        CurrencyFactor := GenJnlLine.GetGenJnlLineToJobCurrencyFactor();
+        ExpectedNonDedVATAmountLCY := Round(GenJnlLine."Non-Deductible VAT Amount" * CurrencyFactor);
+        ExpectedUnitCostLCY := GenJnlLine."Job Unit Cost (LCY)" + Round(ExpectedNonDedVATAmountLCY / GenJnlLine."Job Quantity");
+        ExpectedTotalCostLCY := GenJnlLine."Job Total Cost (LCY)" + ExpectedNonDedVATAmountLCY;
+
+        Assert.AreEqual(
+            ExpectedUnitCostLCY,
+            JobJnlLine."Unit Cost (LCY)",
+            'Unit Cost (LCY) with Non-Deductible VAT amount is not correct when project has FCY');
+        Assert.AreEqual(
+            ExpectedTotalCostLCY,
+            JobJnlLine."Total Cost (LCY)",
+            'Total Cost (LCY) with Non-Deductible VAT amount is not correct when project has FCY');
+    end;
+
     [Test]
