+        WarehousePutAway: TestPage "Warehouse Put-away";
+        QtyPerBox: Decimal;
+        PurchQty: Decimal;
+    begin
+        // [FEATURE] [Put-Away] [Breakbulk] [Breakbulk Filter]
+        // [SCENARIO] When registering a put-away with Breakbulk Filter enabled, all lines (including breakbulk lines) should be registered.
+        Initialize();
+        QtyPerBox := LibraryRandom.RandIntInRange(5, 10);
+        PurchQty := LibraryRandom.RandIntInRange(5, 10);
+
+        // [GIVEN] Full WMS location with Allow Breakbulk = TRUE.
+        LibraryWarehouse.CreateFullWMSLocation(Location, 1);
+        Location.Validate("Allow Breakbulk", true);
+        Location.Modify(true);
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployeeLoc, Location.Code, false);
+
+        // [GIVEN] Item with Base Unit of Measure = "PCS" and alternate Unit of Measure = "BOX". "BOX" contains "X" units of "PCS".
+        // [GIVEN] Put-away Unit of Measure Code in the item is "PCS" (base UOM).
+        LibraryInventory.CreateItem(Item);
+        CreateItemUnitOfMeasure(BoxUnitOfMeasure, Item."No.", QtyPerBox);
+        UpdateItemUOM(Item, BoxUnitOfMeasure.Code, '', Item."Base Unit of Measure");
+
+        // [GIVEN] Create and release a Purchase Order for "Y" boxes.
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Order, '');
+        LibraryPurchase.CreatePurchaseLine(PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item, Item."No.", PurchQty);
+        PurchaseLine.Validate("Location Code", Location.Code);
+        PurchaseLine.Validate("Unit of Measure Code", BoxUnitOfMeasure.Code);
+        PurchaseLine.Modify(true);
+        LibraryPurchase.ReleasePurchaseDocument(PurchaseHeader);
+
+        // [GIVEN] Create and post a Warehouse Receipt.
+        CreateAndPostWarehouseReceiptFromPurchaseOrder(PurchaseHeader);
+
+        // [GIVEN] A Put-away is created with breakbulk lines (Take BOX, Place PCS).
+        FindWarehouseActivityLine(WarehouseActivityLine, WarehouseActivityLine."Source Document"::"Purchase Order", PurchaseHeader."No.", WarehouseActivityLine."Activity Type"::"Put-away");
+        WarehouseActivityHeader.Get(WarehouseActivityLine."Activity Type", WarehouseActivityLine."No.");
+
+        // [GIVEN] The Breakbulk Filter is set to true on the Put-away header.
+        WarehouseActivityHeader.Validate("Breakbulk Filter", true);
+        WarehouseActivityHeader.Modify(true);
+
+        // [WHEN] Open the Put-away page with Breakbulk Filter and invoke Register Put-away action.
+        WarehousePutAway.OpenEdit();
+        WarehousePutAway.GoToRecord(WarehouseActivityHeader);
+        WarehousePutAway.WhseActivityLines.AutofillQtyToHandle.Invoke();
+        WarehousePutAway."&Register Put-away".Invoke();
+        WarehousePutAway.Close();
+
+        // [THEN] All put-away lines are registered (including the breakbulk lines).
+        RegisteredWhseActivityLine.SetRange("Source Document", RegisteredWhseActivityLine."Source Document"::"Purchase Order");
+        RegisteredWhseActivityLine.SetRange("Source No.", PurchaseHeader."No.");
+        RegisteredWhseActivityLine.SetRange("Activity Type", RegisteredWhseActivityLine."Activity Type"::"Put-away");
+        Assert.RecordCount(RegisteredWhseActivityLine, 4); // Take (BOX), Place (PCS - breakbulk), Take (PCS - breakbulk), Place (PCS)
+
+        // [THEN] The put-away document no longer exists (fully registered).
+        WarehouseActivityLine.SetRange("Source Document", WarehouseActivityLine."Source Document"::"Purchase Order");
+        WarehouseActivityLine.SetRange("Source No.", PurchaseHeader."No.");
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::"Put-away");
+        Assert.RecordIsEmpty(WarehouseActivityLine);
+    end;
