+    [Test]
+    [Scope('OnPrem')]
+    [HandlerFunctions('SimpleMessageHandler,WhseSrcCreateDocReqHandler')]
+    procedure ChangeQtyOnLastTakeLineUpdatesCorrectPlaceLine()
+    var
+        CompItem: Record Item;
+        ProdItem: Record Item;
+        Location: Record Location;
+        Bin: array[6] of Record Bin;
+        ProductionOrder: Record "Production Order";
+        ProdOrderLine: Record "Prod. Order Line";
+        ProdOrderComponent: Record "Prod. Order Component";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        TakeLineNo: Integer;
+        PlaceLineNo: Integer;
+        OriginalQty: Decimal;
+        NewQty: Decimal;
+        i: Integer;
+    begin
+        // [SCENARIO] When manually changing the quantity on a Take line in a Warehouse Pick for production consumption,
+        // the corresponding Place line immediately following the Take line should be updated, not the first Place line.
+        Initialize();
+
+        // [GIVEN] Create Location with require pick and Prod. Consump. Whse. Handling set to Warehouse Pick (mandatory).
+        LibraryWarehouse.CreateLocationWMS(Location, true, false, true, false, true);
+        Location.Validate("Prod. Consump. Whse. Handling", Location."Prod. Consump. Whse. Handling"::"Warehouse Pick (mandatory)");
+        for i := 1 to 6 do
+            LibraryWarehouse.CreateBin(Bin[i], Location.Code, LibraryUtility.GenerateGUID(), '', '');
+        Location.Validate("From-Production Bin Code", Bin[6].Code);
+        Location.Validate("To-Production Bin Code", Bin[6].Code);
+        Location.Modify(true);
+
+        // [GIVEN] Create component item with Allow Whse. Overpick and Flushing Method = Pick + Manual.
+        LibraryInventory.CreateItem(CompItem);
+        CompItem.Validate("Flushing Method", CompItem."Flushing Method"::"Pick + Manual");
+        CompItem.Validate("Allow Whse. Overpick", true);
+        CompItem.Modify(true);
+
+        // [GIVEN] Create production item with BOM containing the component.
+        LibraryInventory.CreateItem(ProdItem);
+        ProdItem.Validate("Replenishment System", ProdItem."Replenishment System"::"Prod. Order");
+        ProdItem.Modify(true);
+
+        // [GIVEN] Put 900 qty of component item in 5 different bins (total 4500).
+        OriginalQty := 900;
+        for i := 1 to 5 do
+            CreateAndPostItemJournalLine(CompItem."No.", "Item Ledger Entry Type"::"Positive Adjmt.", OriginalQty, Location.Code, Bin[i].Code, '');
+
+        // [GIVEN] Create Released Production Order requiring 4200 qty of component.
+        CreateAndRefreshProductionOrder(ProductionOrder, "Production Order Status"::Released, "Prod. Order Source Type"::Item, ProdItem."No.", 1, Location.Code);
+        FindFirstProdOrderLine(ProdOrderLine, ProductionOrder);
+
+        // [GIVEN] Add component item to production order with quantity per = 4200 (creates 5 Take/Place pairs of 900 each, except last).
+        CreateProdOrderComponent(ProdOrderComponent, ProdOrderLine, CompItem."No.", 4200);
+        ProdOrderComponent.Validate("Bin Code", Bin[6].Code);
+        ProdOrderComponent.Modify(true);
+
+        // [GIVEN] Create Warehouse Pick for the production order.
+        Commit();
+        LibraryWarehouse.CreateWhsePickFromProduction(ProductionOrder);
+        LibraryVariableStorage.DequeueText();
+
+        // [GIVEN] Find the warehouse pick and identify the last Take/Place pair.
+        WarehouseActivityLine.SetRange("Source No.", ProductionOrder."No.");
+        WarehouseActivityLine.SetRange("Source Document", WarehouseActivityLine."Source Document"::"Prod. Consumption");
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::Pick);
+        WarehouseActivityLine.SetRange("Action Type", WarehouseActivityLine."Action Type"::Take);
+        WarehouseActivityLine.SetRange("Item No.", CompItem."No.");
+        WarehouseActivityLine.FindLast();
+        TakeLineNo := WarehouseActivityLine."Line No.";
+        OriginalQty := WarehouseActivityLine.Quantity;
+
+        // [GIVEN] Find the Place line corresponding to this Take line (it should be the next line after Take).
+        WarehouseActivityLine.SetRange("Action Type", WarehouseActivityLine."Action Type"::Place);
+        WarehouseActivityLine.SetFilter("Line No.", '>%1', TakeLineNo);
+        WarehouseActivityLine.FindFirst();
+        PlaceLineNo := WarehouseActivityLine."Line No.";
+
+        // [WHEN] Change the quantity on the last Take line from 900 to 400.
+        NewQty := 400;
+        WarehouseActivityLine.Get(WarehouseActivityLine."Activity Type"::Pick, WarehouseActivityLine."No.", TakeLineNo);
+        WarehouseActivityLine.Validate(Quantity, NewQty);
+        WarehouseActivityLine.Modify(true);
+
+        // [THEN] The corresponding Place line (immediately after the Take line) should be updated to 400.
+        WarehouseActivityLine.Get(WarehouseActivityLine."Activity Type"::Pick, WarehouseActivityLine."No.", PlaceLineNo);
+        Assert.AreEqual(NewQty, WarehouseActivityLine.Quantity, 'The Place line quantity should be updated to match the Take line quantity.');
+
+        // [THEN] Verify first Place line was NOT changed (should still have original quantity).
+        WarehouseActivityLine.SetRange("Action Type", WarehouseActivityLine."Action Type"::Place);
+        WarehouseActivityLine.SetRange("Line No.");
+        WarehouseActivityLine.FindFirst();
+        if WarehouseActivityLine."Line No." <> PlaceLineNo then
+            Assert.AreEqual(OriginalQty, WarehouseActivityLine.Quantity, 'The first Place line should not have been modified.');
+    end;
