+    [Test]
+    procedure AvailWarningOnAssemblyOrderShouldConsiderDueDate()
+    var
+        AsmItem: Record Item;
+        CompItem: Record Item;
+        BOMComponent: Record "BOM Component";
+        ItemJournalLine: Record "Item Journal Line";
+        AssemblyHeader: array[2] of Record "Assembly Header";
+        AssemblyLine: array[2] of Record "Assembly Line";
+        ItemCheckAvail: Codeunit "Item-Check Avail.";
+        FirstAsmOrderDueDate: Date;
+        SecondAsmOrderDueDate: Date;
+        QtyPerComponent: Decimal;
+    begin
+        // [FEATURE] [Availability Warning]
+        // [SCENARIO] Availability warning on assembly orders should consider Due Dates,
+        // not all future demands. First order with sufficient inventory by its due date
+        // should NOT show availability warning even if future orders create more demand.
+        Initialize();
+
+        // [GIVEN] Assembly item with 1 component where "Qty per" = 2 (each parent needs 2 components)
+        QtyPerComponent := 2;
+        LibraryInventory.CreateItem(AsmItem);
+        AsmItem.Validate("Replenishment System", AsmItem."Replenishment System"::Assembly);
+        AsmItem.Modify(true);
+
+        LibraryInventory.CreateItem(CompItem);
+        LibraryInventory.CreateBOMComponent(
+          BOMComponent, AsmItem."No.", BOMComponent.Type::Item, CompItem."No.", QtyPerComponent, CompItem."Base Unit of Measure");
+
+        // [GIVEN] Post 2 pcs of the component to inventory
+        LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, CompItem."No.", '', '', 2);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+
+        // [GIVEN] First assembly order for 1 pc with Due Date = WorkDate + 1 (needs 2 components, we have 2)
+        FirstAsmOrderDueDate := WorkDate() + 1;
+        LibraryAssembly.CreateAssemblyHeader(AssemblyHeader[1], FirstAsmOrderDueDate, AsmItem."No.", '', 1, '');
+        FindAssemblyLine(AssemblyLine[1], AssemblyHeader[1], CompItem."No.");
+
+        // [GIVEN] Second assembly order for 3 pcs with Due Date = WorkDate + 5 (needs 6 more components)
+        SecondAsmOrderDueDate := WorkDate() + 5;
+        LibraryAssembly.CreateAssemblyHeader(AssemblyHeader[2], SecondAsmOrderDueDate, AsmItem."No.", '', 3, '');
+        FindAssemblyLine(AssemblyLine[2], AssemblyHeader[2], CompItem."No.");
+
+        // [WHEN] Checking availability warning on the first assembly order line
+        // [THEN] The first assembly line should NOT show availability warning
+        // because it has sufficient inventory (2) for its demand (2) by its due date
+        Assert.IsFalse(
+          ItemCheckAvail.AsmOrderLineShowWarning(AssemblyLine[1]),
+          'First assembly order line should NOT show availability warning since sufficient inventory exists by its due date.');
+
+        // [THEN] The second assembly line SHOULD show availability warning
+        // because it needs 6 more components but only 0 are available (2 - 2 from first order = 0)
+        Assert.IsTrue(
+          ItemCheckAvail.AsmOrderLineShowWarning(AssemblyLine[2]),
+          'Second assembly order line should show availability warning since insufficient inventory exists by its due date.');
+
+        NotificationLifecycleMgt.RecallAllNotifications();
+    end;
