--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMItemJournalUOMReset.Codeunit.al
@@ -0,0 +1,178 @@
+codeunit 137799 "SCM Item Journal UOM Reset"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Item Journal] [Unit of Measure] [SCM]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryRandom: Codeunit "Library - Random";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure UnitOfMeasureCodeIsResetWhenItemNoChanges()
+    var
+        Item1: Record Item;
+        Item2: Record Item;
+        UnitOfMeasure1: Record "Unit of Measure";
+        UnitOfMeasure2: Record "Unit of Measure";
+        ItemUnitOfMeasure1: Record "Item Unit of Measure";
+        ItemUnitOfMeasure2: Record "Item Unit of Measure";
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalBatch: Record "Item Journal Batch";
+    begin
+        // [SCENARIO] Unit of Measure Code should be reset when changing Item No. on Item Journal Line to prevent validation errors
+        // [GIVEN] Two items with different Units of Measure
+        Initialize();
+
+        // Create first item with UOM "PCS"
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure1);
+        LibraryInventory.CreateItem(Item1);
+        LibraryInventory.CreateItemUnitOfMeasure(ItemUnitOfMeasure1, Item1."No.", UnitOfMeasure1.Code, 1);
+        Item1.Validate("Base Unit of Measure", UnitOfMeasure1.Code);
+        Item1.Modify(true);
+
+        // Create second item with different UOM "BOX"
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure2);
+        LibraryInventory.CreateItem(Item2);
+        LibraryInventory.CreateItemUnitOfMeasure(ItemUnitOfMeasure2, Item2."No.", UnitOfMeasure2.Code, 1);
+        Item2.Validate("Base Unit of Measure", UnitOfMeasure2.Code);
+        Item2.Modify(true);
+
+        // [GIVEN] Item Journal Line with first item
+        SelectItemJournal(ItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch."Journal Template Name",
+            ItemJournalBatch.Name, ItemJournalLine."Entry Type"::"Positive Adjmt.", Item1."No.", LibraryRandom.RandInt(10));
+
+        // Verify the UOM is set from first item
+        Assert.AreEqual(UnitOfMeasure1.Code, ItemJournalLine."Unit of Measure Code", 'Initial UOM should be set from first item');
+
+        // [WHEN] Changing Item No. to second item with different UOM
+        ItemJournalLine.Validate("Item No.", Item2."No.");
+
+        // [THEN] Unit of Measure Code should be reset and revalidated with the new item's UOM
+        Assert.AreEqual(UnitOfMeasure2.Code, ItemJournalLine."Unit of Measure Code",
+            'Unit of Measure Code should be updated to the new item''s base UOM');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure UnitOfMeasureCodeIsResetWhenItemNoCleared()
+    var
+        Item: Record Item;
+        UnitOfMeasure: Record "Unit of Measure";
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalBatch: Record "Item Journal Batch";
+    begin
+        // [SCENARIO] Unit of Measure Code should be cleared when Item No. is cleared on Item Journal Line
+        Initialize();
+
+        // [GIVEN] An item with specific UOM
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure);
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItemUnitOfMeasure(ItemUnitOfMeasure, Item."No.", UnitOfMeasure.Code, 1);
+        Item.Validate("Base Unit of Measure", UnitOfMeasure.Code);
+        Item.Modify(true);
+
+        // [GIVEN] Item Journal Line with the item
+        SelectItemJournal(ItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch."Journal Template Name",
+            ItemJournalBatch.Name, ItemJournalLine."Entry Type"::"Positive Adjmt.", Item."No.", LibraryRandom.RandInt(10));
+
+        // Verify initial state
+        Assert.AreEqual(UnitOfMeasure.Code, ItemJournalLine."Unit of Measure Code", 'Initial UOM should be set');
+
+        // [WHEN] Clearing the Item No.
+        ItemJournalLine.Validate("Item No.", '');
+
+        // [THEN] Unit of Measure Code should be cleared
+        Assert.AreEqual('', ItemJournalLine."Unit of Measure Code", 'Unit of Measure Code should be cleared when Item No. is cleared');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure NoErrorWhenChangingItemWithIncompatibleUOM()
+    var
+        Item1: Record Item;
+        Item2: Record Item;
+        UnitOfMeasure1: Record "Unit of Measure";
+        UnitOfMeasure2: Record "Unit of Measure";
+        ItemUnitOfMeasure1: Record "Item Unit of Measure";
+        ItemUnitOfMeasure2: Record "Item Unit of Measure";
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalBatch: Record "Item Journal Batch";
+    begin
+        // [SCENARIO] No error should occur when changing Item No. to an item that doesn't have the previous UOM
+        // This reproduces the bug where changing items with different UOMs caused an error
+        Initialize();
+
+        // [GIVEN] First item with UOM "PCS" only (no other UOMs)
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure1);
+        LibraryInventory.CreateItem(Item1);
+        LibraryInventory.CreateItemUnitOfMeasure(ItemUnitOfMeasure1, Item1."No.", UnitOfMeasure1.Code, 1);
+        Item1.Validate("Base Unit of Measure", UnitOfMeasure1.Code);
+        Item1.Modify(true);
+
+        // [GIVEN] Second item with completely different UOM "BOX" only (doesn't have "PCS")
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure2);
+        LibraryInventory.CreateItem(Item2);
+        LibraryInventory.CreateItemUnitOfMeasure(ItemUnitOfMeasure2, Item2."No.", UnitOfMeasure2.Code, 1);
+        Item2.Validate("Base Unit of Measure", UnitOfMeasure2.Code);
+        Item2.Modify(true);
+
+        // [GIVEN] Item Journal Line with first item and its UOM
+        SelectItemJournal(ItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch."Journal Template Name",
+            ItemJournalBatch.Name, ItemJournalLine."Entry Type"::"Positive Adjmt.", Item1."No.", LibraryRandom.RandInt(10));
+
+        // Verify initial UOM
+        Assert.AreEqual(UnitOfMeasure1.Code, ItemJournalLine."Unit of Measure Code", 'Initial UOM should be from first item');
+
+        // [WHEN] Changing to second item (which doesn't support the first item's UOM)
+        // This should NOT throw an error because UOM should be reset before validation
+        ItemJournalLine.Validate("Item No.", Item2."No.");
+
+        // [THEN] No error occurs and UOM is correctly set to the second item's base UOM
+        Assert.AreEqual(UnitOfMeasure2.Code, ItemJournalLine."Unit of Measure Code",
+            'Unit of Measure Code should be updated to new item''s base UOM without error');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Item Journal UOM Reset");
+        LibraryRandom.Init();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Item Journal UOM Reset");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Item Journal UOM Reset");
+    end;
+
+    local procedure SelectItemJournal(var ItemJournalBatch: Record "Item Journal Batch")
+    var
+        ItemJournalTemplate: Record "Item Journal Template";
+    begin
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Item, ItemJournalTemplate.Name);
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+    end;
+}

