+    begin
+        // [FEATURE] [FEFO] [Item Tracking] [Inventory Pick] [Rounding]
+        // [SCENARIO] Creating inventory pick with FEFO for multiple lots with different expiration dates from multiple bins should not lose quantity due to rounding.
+        Initialize();
+
+        // [GIVEN] Location with Require Pick and Pick According to FEFO enabled.
+        LibraryWarehouse.CreateLocationWMS(Location, true, false, true, false, false);
+        Location.Validate("Pick According to FEFO", true);
