+
+        // [GIVEN] Create 3 bins at the location.
+        for i := 1 to 3 do
+            LibraryWarehouse.CreateBin(Bin[i], Location.Code, LibraryUtility.GenerateGUID(), '', '');
+
+        // [GIVEN] Create Item with Lot tracking and Expiration Date.
+        CreateTrackedItem(Item, LibraryUtility.GetGlobalNoSeriesCode(), '', CreateItemTrackingCode(true, false, true));
+
+        // [GIVEN] Create additional Unit of Measure with Qty. per Unit of Measure = 2.888 (non-integer to create rounding).
+        QtyPerUOM := 2.888;
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure);
+        LibraryInventory.CreateItemUnitOfMeasure(ItemUnitOfMeasure, Item."No.", UnitOfMeasure.Code, QtyPerUOM);
+        ItemUnitOfMeasure.Validate("Qty. Rounding Precision", 0.00001);
+        ItemUnitOfMeasure.Modify(true);
+        Item.Validate("Sales Unit of Measure", UnitOfMeasure.Code);
+        Item.Modify(true);
+
+        // [GIVEN] Setup Lot Numbers and Expiration Dates.
+        for i := 1 to 6 do
+            LotNo[i] := LibraryUtility.GenerateGUID();
+
+        ExpirationDate[1] := CalcDate('<-6M>', WorkDate());
+        ExpirationDate[2] := CalcDate('<-5M>', WorkDate());
+        ExpirationDate[3] := CalcDate('<-4M>', WorkDate());
+        ExpirationDate[4] := CalcDate('<-3M>', WorkDate());
+        ExpirationDate[5] := CalcDate('<-2M>', WorkDate());
+        ExpirationDate[6] := CalcDate('<-1M>', WorkDate());
+
+        // [GIVEN] Define inventory quantities per bin and lot (matching the issue scenario).
+        // Bin 1: LOT01, LOT03, LOT06
+        Quantity[1] := 434.97616;
+        BinIndex[1] := 1;
+        LotIndex[1] := 1;
+        Quantity[2] := 17.3126;
+        BinIndex[2] := 1;
+        LotIndex[2] := 3;
+        Quantity[3] := 17.0373;
+        BinIndex[3] := 1;
+        LotIndex[3] := 6;
+        // Bin 2: LOT01, LOT02, LOT03, LOT04
+        Quantity[4] := 4.13394;
+        BinIndex[4] := 2;
+        LotIndex[4] := 1;
+        Quantity[5] := 4.34355;
+        BinIndex[5] := 2;
+        LotIndex[5] := 2;
+        Quantity[6] := 151.33333;
+        BinIndex[6] := 2;
+        LotIndex[6] := 3;
+        Quantity[7] := 40.01221;
+        BinIndex[7] := 2;
+        LotIndex[7] := 4;
+        // Bin 3: LOT02, LOT03, LOT05
+        Quantity[8] := 1.78787;
+        BinIndex[8] := 3;
+        LotIndex[8] := 2;
+        Quantity[9] := 42.73313;
+        BinIndex[9] := 3;
+        LotIndex[9] := 3;
+        Quantity[10] := 4.013;
+        BinIndex[10] := 3;
+        LotIndex[10] := 5;
+
+        // [GIVEN] Post inventory for each lot/bin combination.
+        for i := 1 to 10 do begin
+            LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, Item."No.", Location.Code, Bin[BinIndex[i]].Code, Quantity[i]);
+            LibraryItemTracking.CreateItemJournalLineItemTracking(ReservEntry, ItemJournalLine, '', LotNo[LotIndex[i]], Quantity[i]);
+            ReservEntry.Validate("Expiration Date", ExpirationDate[LotIndex[i]]);
+            ReservEntry.Modify(true);
+            LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+        end;
+
+        // [GIVEN] Create Sales Order with quantity 248 in the Sales UOM (PACK).
+        SalesQty := 248;
+        CreateSalesDocument(SalesLine, SalesLine."Document Type"::Order, Item."No.", Location.Code, SalesQty);
+        SalesLine.Validate("Unit of Measure Code", UnitOfMeasure.Code);
+        SalesLine.Modify(true);
+        SalesHeader.Get(SalesLine."Document Type", SalesLine."Document No.");
+        LibrarySales.ReleaseSalesDocument(SalesHeader);
+
+        // [WHEN] Create Inventory Pick.
+        LibraryWarehouse.CreateInvtPutPickMovement(SalesHeader."Document Type", SalesHeader."No.", false, true, false);
+
+        // [THEN] The total picked quantity in sales UOM equals the demanded quantity without rounding loss.
+        WarehouseActivityLine.SetRange("Source No.", SalesLine."Document No.");
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::"Invt. Pick");
+        WarehouseActivityLine.SetRange("Location Code", Location.Code);
+        WarehouseActivityLine.CalcSums(Quantity);
+        TotalPickQty := WarehouseActivityLine.Quantity;
+        Assert.AreEqual(SalesQty, TotalPickQty, 'Total pick quantity must equal sales order quantity without rounding loss.');
+    end;
