+    [Test]
+    procedure CreateContractEntryNoFilterWithDescendingLineNoOrder()
+    var
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        JobPlanningLine: Record "Job Planning Line";
+        JobPlanningLine2: Record "Job Planning Line";
+        JobPlanningLineFiltered: Record "Job Planning Line";
+        Item: Record Item;
+        SelectionFilterMgt: Codeunit System.Text.SelectionFilterManagement;
+        RecRef: RecordRef;
+        ContractEntryNoFilterWithKey: Text;
+        FirstContractEntryNo: Integer;
+        SecondContractEntryNo: Integer;
+    begin
+        // [FEATURE] [Job Planning Line] [Create Purchase Order]
+        // [SCENARIO] When Job Planning Lines are inserted BEFORE existing lines (lower Line No. but higher Job Contract Entry No.),
+        // the filter generation for Create Purchase Order should produce a valid ascending range filter by using SetCurrentKey.
+        Initialize();
+
+        // [GIVEN] Create a Job with a Job Task.
+        CreateJobAndJobTask(Job, JobTask, false, '');
+        LibraryInventory.CreateItem(Item);
+
+        // [GIVEN] Create first Job Planning Line with high Line No. (e.g., 20000).
+        JobPlanningLine.Init();
+        JobPlanningLine.Validate("Job No.", JobTask."Job No.");
+        JobPlanningLine.Validate("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLine.Validate("Line No.", 20000);
+        JobPlanningLine.Insert(true);
+        JobPlanningLine.Validate("Planning Date", WorkDate());
+        JobPlanningLine.Validate("Line Type", JobPlanningLine."Line Type"::Budget);
+        JobPlanningLine.Validate(Type, JobPlanningLine.Type::Item);
+        JobPlanningLine.Validate("No.", Item."No.");
+        JobPlanningLine.Validate(Quantity, LibraryRandom.RandInt(10));
+        JobPlanningLine.Modify(true);
+        FirstContractEntryNo := JobPlanningLine."Job Contract Entry No.";
+
+        // [GIVEN] Create second Job Planning Line with lower Line No. (inserted BEFORE the first line).
+        // This simulates adding a line BEFORE an existing one, resulting in Line No. order (10000, 20000)
+        // but Job Contract Entry No. order (FirstContractEntryNo, SecondContractEntryNo) where Second > First.
+        JobPlanningLine2.Init();
+        JobPlanningLine2.Validate("Job No.", JobTask."Job No.");
+        JobPlanningLine2.Validate("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLine2.Validate("Line No.", 10000);
+        JobPlanningLine2.Insert(true);
+        JobPlanningLine2.Validate("Planning Date", WorkDate());
+        JobPlanningLine2.Validate("Line Type", JobPlanningLine2."Line Type"::Budget);
+        JobPlanningLine2.Validate(Type, JobPlanningLine2.Type::Item);
+        JobPlanningLine2.Validate("No.", Item."No.");
+        JobPlanningLine2.Validate(Quantity, LibraryRandom.RandInt(10));
+        JobPlanningLine2.Modify(true);
+        SecondContractEntryNo := JobPlanningLine2."Job Contract Entry No.";
+
+        // [VERIFY] Second line has higher Job Contract Entry No. because it was created later.
+        Assert.IsTrue(SecondContractEntryNo > FirstContractEntryNo, 'Second line should have higher Job Contract Entry No.');
+
+        // [WHEN] Generate filter using SetCurrentKey("Job Contract Entry No.") before GetSelectionFilter.
+        // This is the fix: sorting by Job Contract Entry No. ensures the filter is generated correctly.
+        JobPlanningLineFiltered.SetLoadFields("Job Contract Entry No.");
+        JobPlanningLineFiltered.SetRange("Job No.", JobTask."Job No.");
+        JobPlanningLineFiltered.SetRange("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLineFiltered.SetCurrentKey("Job Contract Entry No.");
+        JobPlanningLineFiltered.FindSet();
+        RecRef.GetTable(JobPlanningLineFiltered);
+        ContractEntryNoFilterWithKey := SelectionFilterMgt.GetSelectionFilter(RecRef, JobPlanningLineFiltered.FieldNo("Job Contract Entry No."));
+
+        // [THEN] The filter should return both records when applied.
+        JobPlanningLineFiltered.Reset();
+        JobPlanningLineFiltered.SetFilter("Job Contract Entry No.", ContractEntryNoFilterWithKey);
+        Assert.AreEqual(2, JobPlanningLineFiltered.Count(), 'Filter with SetCurrentKey should return both Job Planning Lines.');
+
+        // [THEN] Verify the filter is in ascending order (lower Contract Entry No. appears first).
+        Assert.IsTrue(StrPos(ContractEntryNoFilterWithKey, Format(FirstContractEntryNo)) < StrPos(ContractEntryNoFilterWithKey, Format(SecondContractEntryNo)),
+            'Filter should have lower Contract Entry No. first (ascending order).');
+    end;
