--- /dev/null
+++ b/App/Layers/W1/Tests/ERM/IssuedReminderEmailTests.Codeunit.al
@@ -0,0 +1,88 @@
+codeunit 134977 "Issued Reminder Email Tests"
+{
+    // Tests to verify that issued reminder emails are correctly linked to customer's sent email history
+    // Bug fix: Issued reminder emails were not appearing in customer's "Sent Emails" history because
+    // 1. Issued Reminder Header was not recognized as a customer account
+    // 2. The field name "Sell-to Customer No." was used instead of "Customer No." which doesn't exist on Issued Reminder Header
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Issued Reminder] [Email]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryUtility: Codeunit "Library - Utility";
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure IssuedReminderHeaderHasCustomerNoFieldNotSellToCustomerNo()
+    var
+        RecRef: RecordRef;
+        DataTypeMgt: Codeunit "Data Type Management";
+        FieldRef: FieldRef;
+    begin
+        // [SCENARIO] Issued Reminder Header should have "Customer No." field but NOT "Sell-to Customer No." field
+        // This validates the core reason for the bug: the code was trying to use "Sell-to Customer No."
+        // which doesn't exist on Issued Reminder Header, causing the customer link to fail
+
+        // [GIVEN] The Issued Reminder Header table
+        RecRef.Open(Database::"Issued Reminder Header");
+
+        // [WHEN] We check for field existence using DataTypeManagement (same as production code)
+        // [THEN] "Customer No." field should exist
+        Assert.IsTrue(DataTypeMgt.FindFieldByName(RecRef, FieldRef, 'Customer No.'),
+            'Customer No. field should exist on Issued Reminder Header');
+
+        // [THEN] "Sell-to Customer No." field should NOT exist - this was the bug
+        Assert.IsFalse(DataTypeMgt.FindFieldByName(RecRef, FieldRef, 'Sell-to Customer No.'),
+            'Sell-to Customer No. field should NOT exist on Issued Reminder Header. ' +
+            'Using this field name would fail to find the customer and email would not be linked to customer history.');
+
+        RecRef.Close();
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure IssuedReminderEmailShouldUseCustomerNoFieldForCustomerLookup()
+    var
+        IssuedReminderHeader: Record "Issued Reminder Header";
+        Customer: Record Customer;
+        RecRef: RecordRef;
+        DataTypeMgt: Codeunit "Data Type Management";
+        FieldRef: FieldRef;
+        CustomerNo: Code[20];
+    begin
+        // [SCENARIO] When sending email for Issued Reminder, the customer should be found using "Customer No." field
+        // to correctly link the email to the customer's sent email history
+        // This test verifies that the fix works by confirming the customer can be retrieved from Issued Reminder Header
+
+        // [GIVEN] A customer
+        LibrarySales.CreateCustomer(Customer);
+        CustomerNo := Customer."No.";
+
+        // [GIVEN] An Issued Reminder Header with the customer
+        IssuedReminderHeader.Init();
+        IssuedReminderHeader."No." := LibraryUtility.GenerateGUID();
+        IssuedReminderHeader."Customer No." := CustomerNo;
+        IssuedReminderHeader.Insert();
+
+        // [WHEN] We try to find the customer using the "Customer No." field (as the fix does)
+        RecRef.GetTable(IssuedReminderHeader);
+
+        // [THEN] We should be able to find the field and get the customer
+        Assert.IsTrue(DataTypeMgt.FindFieldByName(RecRef, FieldRef, 'Customer No.'),
+            'Should be able to find Customer No. field on Issued Reminder Header');
+        Assert.AreEqual(CustomerNo, Format(FieldRef.Value()),
+            'Customer No. field should contain the correct customer number');
+        Assert.IsTrue(Customer.Get(Format(FieldRef.Value())),
+            'Should be able to retrieve the customer using the Customer No. field value');
+
+        // Cleanup
+        IssuedReminderHeader.Delete();
+        RecRef.Close();
+    end;
+}

