index 70c0068a..8c8bf373 100644
--- a/App/Layers/W1/Tests/SCM/SCMInventoryOrderTracking.Codeunit.al
+++ b/App/Layers/W1/Tests/SCM/SCMInventoryOrderTracking.Codeunit.al
@@ -645,6 +645,125 @@ codeunit 137250 "SCM Inventory Order Tracking"
         LibraryVariableStorage.AssertEmpty();
     end;

+    [Test]
+    [HandlerFunctions('MessageHandler')]
+    [Scope('OnPrem')]
+    procedure CalcReservQtyWithMultipleTrackingEntriesAndNonBaseUOM()
+    var
+        Item: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        ReservationEntry: Record "Reservation Entry";
+        UOMMgt: Codeunit "Unit of Measure Management";
+        QtyPerUOM: Decimal;
+        QtyBase1: Decimal;
+        QtyBase2: Decimal;
+        QtyBase3: Decimal;
+        TotalQtyBase: Decimal;
+        EntryNo: Integer;
+        ExpectedTotalQty: Decimal;
+        ActualTotalQty: Decimal;
+    begin
+        // [FEATURE] [Order Tracking] [Unit of Measure]
+        // [SCENARIO] When multiple Tracking reservation entries exist for a sales line with non-base UOM,
+        // the Quantity field should be correctly calculated without rounding errors when Quantity (Base) is validated.
+        // This is a regression test for a bug where CalcReservationQuantity only considered Reservation status entries,
+        // but not Tracking status entries, causing incorrect rounding when multiple tracking entries are summed.
+        // The bug caused the sum of Quantity to be 12.00001 instead of exactly 12 when split into 3 tracking entries.
+        Initialize();
+
+        // [GIVEN] Item with "Order Tracking Policy" = "Tracking & Action Msg." and an alternate UOM (CASE = 24 PCS)
+        LibraryVariableStorage.Enqueue(OrderTrackingPolicyMsg);
+        CreateItem(Item, Item."Replenishment System"::Purchase, Item."Order Tracking Policy"::"Tracking & Action Msg.");
+        QtyPerUOM := 24;
+        LibraryInventory.CreateItemUnitOfMeasureCode(ItemUnitOfMeasure, Item."No.", QtyPerUOM);
+        Item.Validate("Sales Unit of Measure", ItemUnitOfMeasure.Code);
+        Item.Modify(true);
+
+        // [GIVEN] A Sales Order for 12 CASE (288 PCS in base UOM)
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, LibrarySales.CreateCustomerNo());
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", 12);
+        SalesLine.Validate("Unit of Measure Code", ItemUnitOfMeasure.Code);
+        SalesLine.Modify(true);
+
+        // [GIVEN] Three Tracking reservation entries that would cause rounding issues
+        // Using values where each individual division creates a fractional value:
+        // 13/24 = 0.54167, 137/24 = 5.70833, 138/24 = 5.75
+        // Without the fix, when the third entry is validated, CalcReservationQuantity wouldn't consider
+        // the first two Tracking entries in its sum, causing an incorrect Quantity calculation.
+        QtyBase1 := 13;
+        QtyBase2 := 137;
+        QtyBase3 := 138;
+        TotalQtyBase := QtyBase1 + QtyBase2 + QtyBase3; // 288
+
+        // Create tracking reservation entries manually
+        if ReservationEntry.FindLast() then;
+        EntryNo := ReservationEntry."Entry No.";
+
+        // First tracking entry - inserted directly with calculated Quantity
+        CreateTrackingReservationEntry(
+            ReservationEntry, EntryNo + 1, SalesLine, -QtyBase1, QtyPerUOM);
+
+        // Second tracking entry - inserted directly with calculated Quantity
+        CreateTrackingReservationEntry(
+            ReservationEntry, EntryNo + 2, SalesLine, -QtyBase2, QtyPerUOM);
+
+        // [WHEN] Third tracking entry is created and Quantity (Base) is validated
+        // This triggers CalcReservationQuantity which should now include Tracking status entries
+        ReservationEntry.Init();
+        ReservationEntry."Entry No." := EntryNo + 3;
+        ReservationEntry.Positive := false;
+        ReservationEntry."Item No." := Item."No.";
+        ReservationEntry."Source Type" := DATABASE::"Sales Line";
+        ReservationEntry."Source Subtype" := SalesLine."Document Type".AsInteger();
+        ReservationEntry."Source ID" := SalesLine."Document No.";
+        ReservationEntry."Source Batch Name" := '';
+        ReservationEntry."Source Prod. Order Line" := 0;
+        ReservationEntry."Source Ref. No." := SalesLine."Line No.";
+        ReservationEntry."Reservation Status" := ReservationEntry."Reservation Status"::Tracking;
+        ReservationEntry."Qty. per Unit of Measure" := QtyPerUOM;
+        ReservationEntry.Insert(true);
+        ReservationEntry.Validate("Quantity (Base)", -QtyBase3);
+        ReservationEntry.Modify(true);
+
+        // [THEN] The sum of Quantity across all three tracking entries should be exactly -12
+        // With the fix, CalcReservationQuantity considers existing Tracking entries when calculating
+        // the new Quantity, ensuring proper rounding of the total.
+        ExpectedTotalQty := -Round(TotalQtyBase / QtyPerUOM, UOMMgt.QtyRndPrecision());
+        ReservationEntry.Reset();
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        ReservationEntry.SetRange("Source Type", DATABASE::"Sales Line");
+        ReservationEntry.SetRange("Source ID", SalesLine."Document No.");
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Tracking);
+        ReservationEntry.CalcSums(Quantity);
+        ActualTotalQty := ReservationEntry.Quantity;
+
+        Assert.AreEqual(ExpectedTotalQty, ActualTotalQty,
+            'The sum of Quantity across tracking entries should be exactly -12, not off by a rounding error.');
+    end;
+
+    local procedure CreateTrackingReservationEntry(var ReservationEntry: Record "Reservation Entry"; EntryNo: Integer; SalesLine: Record "Sales Line"; QtyBase: Decimal; QtyPerUOM: Decimal)
+    var
+        UOMMgt: Codeunit "Unit of Measure Management";
+    begin
+        ReservationEntry.Init();
+        ReservationEntry."Entry No." := EntryNo;
+        ReservationEntry.Positive := QtyBase > 0;
+        ReservationEntry."Item No." := SalesLine."No.";
+        ReservationEntry."Source Type" := DATABASE::"Sales Line";
+        ReservationEntry."Source Subtype" := SalesLine."Document Type".AsInteger();
+        ReservationEntry."Source ID" := SalesLine."Document No.";
+        ReservationEntry."Source Batch Name" := '';
+        ReservationEntry."Source Prod. Order Line" := 0;
+        ReservationEntry."Source Ref. No." := SalesLine."Line No.";
+        ReservationEntry."Reservation Status" := ReservationEntry."Reservation Status"::Tracking;
+        ReservationEntry."Qty. per Unit of Measure" := QtyPerUOM;
+        ReservationEntry."Quantity (Base)" := QtyBase;
+        ReservationEntry.Quantity := Round(QtyBase / QtyPerUOM, UOMMgt.QtyRndPrecision());
+        ReservationEntry.Insert(true);
+    end;
+
     local procedure Initialize()
     var
         LibraryERMCountryData: Codeunit "Library - ERM Country Data";

