+    var
+        TrialBalanceBuffer: Record "EXR Trial Balance Buffer";
+    begin
+        // [SCENARIO] When validating Net Change and Balance fields, the opposite Debit/Credit fields should be cleared
+        // This prevents repeated/stale values when the buffer record is reused across dimension breakdowns
+        // [GIVEN] A Trial Balance Buffer with a positive Net Change (Debit scenario)
+        TrialBalanceBuffer.Init();
+        TrialBalanceBuffer."G/L Account No." := 'TEST001';
+        TrialBalanceBuffer.Validate("Net Change", 1000);
+        TrialBalanceBuffer.Validate(Balance, 500);
+
+        // [THEN] Debit fields should have the positive values, Credit fields should be zero
+        Assert.AreEqual(1000, TrialBalanceBuffer."Net Change (Debit)", 'Net Change (Debit) should be set for positive Net Change');
+        Assert.AreEqual(0, TrialBalanceBuffer."Net Change (Credit)", 'Net Change (Credit) should be zero for positive Net Change');
+        Assert.AreEqual(500, TrialBalanceBuffer."Balance (Debit)", 'Balance (Debit) should be set for positive Balance');
+        Assert.AreEqual(0, TrialBalanceBuffer."Balance (Credit)", 'Balance (Credit) should be zero for positive Balance');
+
+        // [WHEN] The same buffer is reused with a negative Net Change (Credit scenario)
+        // This simulates what happens when the buffer is reused across dimension breakdowns
+        TrialBalanceBuffer.Validate("Net Change", -750);
+        TrialBalanceBuffer.Validate(Balance, -300);
+
+        // [THEN] Credit fields should have the absolute values, Debit fields should be cleared to zero
+        Assert.AreEqual(0, TrialBalanceBuffer."Net Change (Debit)", 'Net Change (Debit) should be cleared when Net Change becomes negative');
+        Assert.AreEqual(750, TrialBalanceBuffer."Net Change (Credit)", 'Net Change (Credit) should be set for negative Net Change');
+        Assert.AreEqual(0, TrialBalanceBuffer."Balance (Debit)", 'Balance (Debit) should be cleared when Balance becomes negative');
+        Assert.AreEqual(300, TrialBalanceBuffer."Balance (Credit)", 'Balance (Credit) should be set for negative Balance');
+
+        // [WHEN] The buffer is reused again with a positive value
+        TrialBalanceBuffer.Validate("Net Change", 2000);
+        TrialBalanceBuffer.Validate(Balance, 1500);
+
+        // [THEN] Debit fields should have the values, Credit fields should be cleared to zero
+        Assert.AreEqual(2000, TrialBalanceBuffer."Net Change (Debit)", 'Net Change (Debit) should be set when Net Change becomes positive again');
+        Assert.AreEqual(0, TrialBalanceBuffer."Net Change (Credit)", 'Net Change (Credit) should be cleared when Net Change becomes positive');
+        Assert.AreEqual(1500, TrialBalanceBuffer."Balance (Debit)", 'Balance (Debit) should be set when Balance becomes positive again');
+        Assert.AreEqual(0, TrialBalanceBuffer."Balance (Credit)", 'Balance (Credit) should be cleared when Balance becomes positive');
+    end;
+
