+        Assert.AreEqual(600, TrialBalanceBuffer."Last Period Bal. (Debit)", 'Last Period Bal. (Debit) should be set for positive value');
+        Assert.AreEqual(0, TrialBalanceBuffer."Last Period Bal. (Credit)", 'Last Period Bal. (Credit) should be zero for positive value');
+
+        // [WHEN] The buffer is reused with negative Last Period values
