+
+    [Test]
+    [HandlerFunctions('ItemChargeAssignmentSalesHandler,SuggestItemChargeAssgntByAmountHandler,PostedSalesDocumentLinesHandler')]
+    [Scope('OnPrem')]
+    procedure GetPostedDocLinesToReverseWithItemChargeAndDefaultQtyToShipBlank()
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+        SalesHeader: Record "Sales Header";
+        SalesHeaderReturnOrder: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        Item: Record Item;
+        ItemCharge: Record "Item Charge";
+        Quantity: Decimal;
+    begin
+        // [FEATURE] [Sales Return Order] [Get Posted Document Lines to Reverse] [Item Charge]
+        // [SCENARIO] Item Charge line can be copied to Sales Return Order using Get Posted Document Lines to Reverse
+        // when Default Quantity to Ship is set to Blank in Sales & Receivables Setup.
+        Initialize();
+
+        // [GIVEN] "Default Quantity to Ship" is set to "Blank" in Sales & Receivables Setup
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup.Validate("Default Quantity to Ship", SalesReceivablesSetup."Default Quantity to Ship"::Blank);
+        SalesReceivablesSetup.Modify(true);
+
+        // [GIVEN] Create Sales Order with Item line (Qty: 25) and Item Charge line (Qty: 25)
+        Quantity := LibraryRandom.RandIntInRange(10, 30);
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItemCharge(ItemCharge);
+
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, LibrarySales.CreateCustomerNo());
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", Quantity);
+        SalesLine.Validate("Unit Price", LibraryRandom.RandDec(100, 2));
+        SalesLine.Modify(true);
+
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::"Charge (Item)", ItemCharge."No.", Quantity);
+        SalesLine.Validate("Unit Price", LibraryRandom.RandDec(100, 2));
+        SalesLine.Modify(true);
+
+        // [GIVEN] Carry out Item Charge Assignment
+        SalesLine.ShowItemChargeAssgnt();
+
+        // [GIVEN] Post (Ship and Invoice) the Sales Order
+        LibrarySales.PostSalesDocument(SalesHeader, true, true);
+
+        // [GIVEN] Create Sales Return Order for the same Customer
+        LibrarySales.CreateSalesHeader(
+            SalesHeaderReturnOrder, SalesHeaderReturnOrder."Document Type"::"Return Order", SalesHeader."Sell-to Customer No.");
+
+        // [WHEN] Run Get Posted Document Lines to Reverse and select both lines (item and charge item)
+        LibraryVariableStorage.Enqueue(1); // Option for Posted Invoices
+        SalesHeaderReturnOrder.GetPstdDocLinesToReverse();
+
+        // [THEN] Both lines should be copied without error
+        SalesLine.Reset();
+        SalesLine.SetRange("Document Type", SalesHeaderReturnOrder."Document Type");
+        SalesLine.SetRange("Document No.", SalesHeaderReturnOrder."No.");
+        SalesLine.SetRange(Type, SalesLine.Type::Item);
+        Assert.RecordIsNotEmpty(SalesLine);
