+
+    [Test]
+    [HandlerFunctions('ItemChargeAssignmentPurchHandler,SuggestItemChargeAssgntByAmountHandler,PostedPurchDocumentLinesHandler')]
+    [Scope('OnPrem')]
+    procedure GetPostedDocLinesToReversePurchWithItemChargeAndDefaultQtyToReceiveBlank()
+    var
+        PurchasesPayablesSetup: Record "Purchases & Payables Setup";
