+        PaymentAmount2: Decimal;
+    begin
+        // [SCENARIO] Reconcile Cust. and Vend. Accs Report shows correct amounts when multiple posting groups are used at entry level.
+        // [GIVEN] Multiple posting groups are enabled and a customer has entries with different posting groups.
+
+        // Setup: Enable Allow Multiple Posting Groups.
+        Initialize();
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup."Allow Multiple Posting Groups" := true;
+        SalesReceivablesSetup.Modify();
+
+        // Create two Customer Posting Groups with different Receivables Accounts.
+        LibrarySales.CreateCustomerPostingGroup(CustomerPostingGroup[1]);
+        LibrarySales.CreateCustomerPostingGroup(CustomerPostingGroup[2]);
+        LibrarySales.CreateAltCustomerPostingGroup(CustomerPostingGroup[1].Code, CustomerPostingGroup[2].Code);
+
+        // Create Customer with Allow Multiple Posting Groups enabled, using first posting group as default.
+        LibrarySales.CreateCustomer(Customer);
+        Customer.Validate("Customer Posting Group", CustomerPostingGroup[1].Code);
+        Customer.Validate("Allow Multiple Posting Groups", true);
+        Customer.Modify(true);
+
+        // Create and post two payments for the same customer with different posting groups.
+        PaymentAmount1 := LibraryRandom.RandDecInRange(100, 200, 2);
+        PaymentAmount2 := LibraryRandom.RandDecInRange(300, 400, 2);
+
+        LibraryERM.SelectGenJnlBatch(GenJournalBatch);
+        LibraryERM.ClearGenJournalLines(GenJournalBatch);
+
+        // First payment with default posting group.
+        LibraryERM.CreateGeneralJnlLineWithBalAcc(
+            GenJournalLine, GenJournalBatch."Journal Template Name", GenJournalBatch.Name,
+            GenJournalLine."Document Type"::Payment, GenJournalLine."Account Type"::Customer, Customer."No.",
+            GenJournalLine."Bal. Account Type"::"G/L Account", LibraryERM.CreateGLAccountNo(), PaymentAmount1);
+        GenJournalLine.Validate("Posting Group", CustomerPostingGroup[1].Code);
+        GenJournalLine.Modify(true);
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
+
+        // Second payment with alternate posting group.
+        LibraryERM.CreateGeneralJnlLineWithBalAcc(
+            GenJournalLine, GenJournalBatch."Journal Template Name", GenJournalBatch.Name,
+            GenJournalLine."Document Type"::Payment, GenJournalLine."Account Type"::Customer, Customer."No.",
+            GenJournalLine."Bal. Account Type"::"G/L Account", LibraryERM.CreateGLAccountNo(), PaymentAmount2);
+        GenJournalLine.Validate("Posting Group", CustomerPostingGroup[2].Code);
+        GenJournalLine.Modify(true);
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
+
+        // Exercise: Run report for first posting group's receivables account.
+        Clear(ReconcileCustAndVendAccs);
+        GLAccount.SetRange("No.", CustomerPostingGroup[1]."Receivables Account");
+        GLAccount.SetRange("Date Filter", WorkDate());
+        GLAccount.FindFirst();
+        ReconcileCustAndVendAccs.SetTableView(GLAccount);
+        Commit();
+        ReconcileCustAndVendAccs.Run();
+
+        // Verify: Report shows only PaymentAmount1 for first posting group (entry-level, not customer-level).
+        LibraryReportDataset.LoadDataSetFile();
+        LibraryReportDataset.SetRange('ReconCustVendBufferPostingGroup', CustomerPostingGroup[1].Code);
+        if not LibraryReportDataset.GetNextRow() then
+            Error(RowNotFoundErr, 'ReconCustVendBufferPostingGroup', CustomerPostingGroup[1].Code);
+        LibraryReportDataset.AssertCurrentRowValueEquals('Amount', PaymentAmount1);
+
+        // Exercise: Run report for second posting group's receivables account.
+        Clear(ReconcileCustAndVendAccs);
+        GLAccount.SetRange("No.", CustomerPostingGroup[2]."Receivables Account");
+        GLAccount.SetRange("Date Filter", WorkDate());
+        GLAccount.FindFirst();
+        ReconcileCustAndVendAccs.SetTableView(GLAccount);
+        Commit();
+        ReconcileCustAndVendAccs.Run();
+
+        // Verify: Report shows only PaymentAmount2 for second posting group (entry-level, not customer-level).
+        LibraryReportDataset.LoadDataSetFile();
+        LibraryReportDataset.SetRange('ReconCustVendBufferPostingGroup', CustomerPostingGroup[2].Code);
+        if not LibraryReportDataset.GetNextRow() then
+            Error(RowNotFoundErr, 'ReconCustVendBufferPostingGroup', CustomerPostingGroup[2].Code);
+        LibraryReportDataset.AssertCurrentRowValueEquals('Amount', PaymentAmount2);
+    end;
+
