+    [Test]
+    procedure VerifyMfgOverheadExpCostWithMultipleProdOrderLinesForSameItem()
+    var
+        RawItem: Record Item;
+        FGItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderLine: Record "Prod. Order Line";
+        MfgCostCalcMgt: Codeunit "Mfg. Cost Calculation Mgt.";
+        ShareOfTotalCapCost: Decimal;
+        ExpMatCost: Decimal;
+        ExpCapDirCost: Decimal;
+        ExpSubDirCost: Decimal;
+        ExpCapOvhdCost: Decimal;
+        ExpMfgOvhdCost: Decimal;
+        RawUnitCost: Decimal;
+        IndirectCostPct: Decimal;
+        LineQty: Decimal;
+        ExpectedMfgOverhead: Decimal;
+        ExpectedMaterialCost: Decimal;
+    begin
+        // [SCENARIO] Manufacturing overhead in Production Order Statistics must be correct when production order has multiple lines for the same item.
+        // Bug: With two lines (Qty 10 each), the manufacturing overhead was incorrectly calculated as 300 instead of 200 (10% of 2000).
+        Initialize();
+
+        // [GIVEN] Set fixed values for reproducibility: Raw item Unit Cost = 100, Indirect Cost % = 10, Line Qty = 10
+        RawUnitCost := 100;
+        IndirectCostPct := 10;
+        LineQty := 10;
+
+        // [GIVEN] Create a raw material item with Unit Cost = 100
+        LibraryInventory.CreateItem(RawItem);
+        RawItem.Validate("Unit Cost", RawUnitCost);
+        RawItem.Modify(true);
+
+        // [GIVEN] Create a finished goods item with Indirect Cost % = 10
+        LibraryInventory.CreateItem(FGItem);
+        FGItem.Validate("Replenishment System", FGItem."Replenishment System"::"Prod. Order");
+        FGItem.Validate("Indirect Cost %", IndirectCostPct);
+
+        // [GIVEN] Create a Production BOM with RAW item (Qty Per = 1)
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, RawItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, RawItem."No.", 1);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+
+        // [GIVEN] Assign Production BOM to FG item
+        FGItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FGItem.Modify(true);
+
+        // [GIVEN] Create a Released Production Order (without auto-refreshing lines)
+        LibraryManufacturing.CreateProductionOrder(ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, FGItem."No.", 2 * LineQty);
+
+        // [GIVEN] Create two production order lines for the same FG item with Qty 10 each (total 20)
+        LibraryManufacturing.CreateProdOrderLine(ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.", FGItem."No.", '', '', LineQty);
+        LibraryManufacturing.CreateProdOrderLine(ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.", FGItem."No.", '', '', LineQty);
+
+        // [WHEN] Refresh Production Order without recalculating lines
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, false, true, true, false);
+
+        // [THEN] Calculate expected costs: Material Cost = 100 * 1 * 20 = 2000, Manufacturing Overhead = 10% of 2000 = 200
+        ExpectedMaterialCost := RawUnitCost * 1 * (2 * LineQty);
+        ExpectedMfgOverhead := ExpectedMaterialCost * IndirectCostPct / 100;
+
+        // [THEN] Calculate actual costs using the same logic as Production Order Statistics page
+        ExpMatCost := 0;
+        ExpCapDirCost := 0;
+        ExpSubDirCost := 0;
+        ExpCapOvhdCost := 0;
+        ExpMfgOvhdCost := 0;
+        ProdOrderLine.SetRange(Status, ProductionOrder.Status);
+        ProdOrderLine.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderLine.SetRange("Planning Level Code", 0);
+        ProdOrderLine.SetFilter("Item No.", '<>%1', '');
+        if ProdOrderLine.FindSet() then
+            repeat
+                MfgCostCalcMgt.CalcShareOfTotalCapCost(ProdOrderLine, ShareOfTotalCapCost);
+                MfgCostCalcMgt.CalcProdOrderLineExpCost(
+                    ProdOrderLine, ShareOfTotalCapCost,
+                    ExpMatCost, ExpCapDirCost, ExpSubDirCost, ExpCapOvhdCost, ExpMfgOvhdCost);
+            until ProdOrderLine.Next() = 0;
+
+        // [THEN] Verify Material Cost is 2000
+        Assert.AreEqual(
+            ExpectedMaterialCost,
+            ExpMatCost,
+            StrSubstNo(MaterialCostMustBeEqualErr, ExpectedMaterialCost, FGItem."No."));
+
+        // [THEN] Verify Manufacturing Overhead is 200 (10% of 2000), not 300 (bug caused by multiple lines)
+        Assert.AreEqual(
+            ExpectedMfgOverhead,
+            ExpMfgOvhdCost,
+            StrSubstNo(MfgOverheadCostMustBeEqualErr, ExpectedMfgOverhead, FGItem."No."));
+    end;
+
     local procedure Initialize()
     begin
         LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Production Orders IV");

