+    [Test]
+    [Scope('OnPrem')]
+    procedure ExtendedTextLinesCarriedOverForMultipleItemsFromBlanketOrderToOrder()
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        SalesOrderLine: Record "Sales Line";
+        ExtendedTextHeader: array[3] of Record "Extended Text Header";
+        ExtendedTextLine: array[3] of Record "Extended Text Line";
+        Item: array[3] of Record Item;
+        TransferExtendedText: Codeunit "Transfer Extended Text";
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+        i: Integer;
+        SalesOrderNo: Code[20];
+        ExtendedTextLineCount: Integer;
+    begin
+        // [SCENARIO] When multiple items with extended text are added to a Blanket Sales Order and Make Order is used,
+        // all Extended text lines should be carried out to the sales order.
+        // [FEATURE] [Blanket Order] [Sales] [Extended Text]
+
+        // [GIVEN] Setup and create 3 items with extended text enabled for blanket orders
+        Initialize();
+        UpdateSalesReceivablesSetup(SalesReceivablesSetup."Default Posting Date"::"Work Date", false);
+
+        for i := 1 to 3 do begin
+            LibraryInventory.CreateItem(Item[i]);
+            Item[i].Validate("Automatic Ext. Texts", false);
+            Item[i].Modify(true);
+
+            LibraryInventory.CreateExtendedTextHeaderItem(ExtendedTextHeader[i], Item[i]."No.");
+            ExtendedTextHeader[i].Validate("Sales Blanket Order", true);
+            ExtendedTextHeader[i].Modify(true);
+
+            LibraryInventory.CreateExtendedTextLineItem(ExtendedTextLine[i], ExtendedTextHeader[i]);
+            ExtendedTextLine[i].Validate(Text, 'Extended Text for ' + Item[i]."No.");
+            ExtendedTextLine[i].Modify(true);
+        end;
+
+        // [GIVEN] Create a Blanket Sales Order with 3 lines (one for each item) and insert extended text for each
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::"Blanket Order", LibrarySales.CreateCustomerNo());
+
+        for i := 1 to 3 do begin
+            LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item[i]."No.", LibraryRandom.RandInt(10));
+            SalesLine.Validate("Qty. to Ship", SalesLine.Quantity);
+            SalesLine.Modify(true);
+            TransferExtendedText.SalesCheckIfAnyExtText(SalesLine, true);
+            TransferExtendedText.InsertSalesExtText(SalesLine);
+        end;
+
+        // [WHEN] Create Sales Order from Blanket Sales Order
+        CODEUNIT.Run(CODEUNIT::"Blanket Sales Order to Order", SalesHeader);
+
+        // [THEN] Find the created Sales Order
+        SalesOrderLine.SetRange("Blanket Order No.", SalesHeader."No.");
+        SalesOrderLine.SetRange("Document Type", SalesOrderLine."Document Type"::Order);
+        SalesOrderLine.FindFirst();
+        SalesOrderNo := SalesOrderLine."Document No.";
+
+        // [THEN] Verify all 3 extended text lines are carried over to the sales order
+        SalesOrderLine.Reset();
+        SalesOrderLine.SetRange("Document Type", SalesOrderLine."Document Type"::Order);
+        SalesOrderLine.SetRange("Document No.", SalesOrderNo);
+        SalesOrderLine.SetRange(Type, SalesOrderLine.Type::" ");
+        SalesOrderLine.SetFilter("Attached to Line No.", '<>0');
+        ExtendedTextLineCount := SalesOrderLine.Count();
+
+        Assert.AreEqual(3, ExtendedTextLineCount, 'All 3 extended text lines should be carried over from Blanket Order to Sales Order');
+    end;
 }

