+    [Test]
+    [Scope('OnPrem')]
+    procedure CommentsOnProdBOMLineWithPositionAreCopiedCorrectlyWhenSameItemListedTwice()
+    var
+        ProdItem: Record Item;
+        CompItem: Record Item;
+        UnitOfMeasure: Record "Unit of Measure";
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionBOMLine2: Record "Production BOM Line";
+        Salesheader: Record "Sales Header";
+        ProductionBOMCommentLine: Record "Production BOM Comment Line";
+        ProdOrderCompCmtLine: Record "Prod. Order Comp. Cmt Line";
+        ProdOrderComponent: Record "Prod. Order Component";
+        RequisitionLine: Record "Requisition Line";
+        Comment1: Text[80];
+        Comment2: Text[80];
+        Position1: Code[10];
+        Position2: Code[10];
+    begin
+        // [SCENARIO] When Calculate Regenerative Planning and Carry Out Action in Planning Worksheet,
+        // Comments on Production BOM Lines with the same Item but different Position values should be
+        // correctly copied to each corresponding Prod Order Component.
+        Initialize();
+
+        // [GIVEN] Create Unit of Measure Code.
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure);
+
+        // [GIVEN] Create one Component Item.
+        CreateItemWithReorderPolicy(CompItem, UnitOfMeasure, ItemUnitOfMeasure, CompItem."Replenishment System"::Purchase, CompItem."Reordering Policy"::" ");
+
+        // [GIVEN] Create Production Item.
+        CreateItemWithReorderPolicy(ProdItem, UnitOfMeasure, ItemUnitOfMeasure, ProdItem."Replenishment System"::"Prod. Order", ProdItem."Reordering Policy"::Order);
+
+        // [GIVEN] Create Production BOM Header.
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ProdItem."Base Unit of Measure");
+
+        // [GIVEN] Set different Position values.
+        Position1 := 'POS1';
+        Position2 := 'POS2';
+
+        // [GIVEN] Create first Production BOM Line for the component item with Position1.
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader,
+            ProductionBOMLine,
+            '',
+            ProductionBOMLine.Type::Item,
+            CompItem."No.",
+            LibraryRandom.RandIntInRange(1, 5));
+        ProductionBOMLine.Validate(Position, Position1);
+        ProductionBOMLine.Modify(true);
+
+        // [GIVEN] Create second Production BOM Line for the same component item with Position2.
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader,
+            ProductionBOMLine2,
+            '',
+            ProductionBOMLine2.Type::Item,
+            CompItem."No.",
+            LibraryRandom.RandIntInRange(1, 5));
+        ProductionBOMLine2.Validate(Position, Position2);
+        ProductionBOMLine2.Modify(true);
+
+        // [GIVEN] Create distinct comments for each BOM line.
+        Comment1 := 'Test Comment for Position 1';
+        CreateProductionBOMCommentLineWithComment(ProductionBOMLine, Comment1);
+
+        Comment2 := 'Test Comment for Position 2';
+        CreateProductionBOMCommentLineWithComment(ProductionBOMLine2, Comment2);
+
+        // [GIVEN] Update Production BOM Status.
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+
+        // [GIVEN] Assign Production BOM No. to Production Item.
+        ProdItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ProdItem.Modify(true);
+
+        // [GIVEN] Create Sales Order.
+        CreateSalesOrder(Salesheader, ProdItem);
+        LibrarySales.ReleaseSalesDocument(Salesheader);
+
+        // [GIVEN] Run Calculate Regenerative Plan.
+        RunCalculateRegenerativePlan(ProdItem."No.", '');
+
+        // [GIVEN] Accept Action Message on Requisition Line.
+        AcceptActionMessageOnReqLine(RequisitionLine, ProdItem."No.");
+
+        // [WHEN] Run Carry Out Action Plan to create Planned Production Order.
+        CarryOutActionPlanForPlannedProdOrder(RequisitionLine);
+
+        // [THEN] Find Prod. Order Components for the component item.
+        ProdOrderComponent.SetRange(Status, ProdOrderComponent.Status::Planned);
+        ProdOrderComponent.SetRange("Item No.", CompItem."No.");
+        Assert.RecordCount(ProdOrderComponent, 2);
+
+        // [THEN] Verify that the first component (Position1) has the correct comment (Comment1).
+        ProdOrderComponent.SetRange(Position, Position1);
+        ProdOrderComponent.FindFirst();
+        ProdOrderCompCmtLine.SetRange(Status, ProdOrderComponent.Status);
+        ProdOrderCompCmtLine.SetRange("Prod. Order No.", ProdOrderComponent."Prod. Order No.");
+        ProdOrderCompCmtLine.SetRange("Prod. Order Line No.", ProdOrderComponent."Prod. Order Line No.");
+        ProdOrderCompCmtLine.SetRange("Prod. Order BOM Line No.", ProdOrderComponent."Line No.");
+        ProdOrderCompCmtLine.FindFirst();
+        Assert.AreEqual(Comment1, ProdOrderCompCmtLine.Comment, 'Comment for Position 1 should match');
+
+        // [THEN] Verify that the second component (Position2) has the correct comment (Comment2).
+        ProdOrderComponent.SetRange(Position, Position2);
+        ProdOrderComponent.FindFirst();
+        ProdOrderCompCmtLine.SetRange("Prod. Order BOM Line No.", ProdOrderComponent."Line No.");
+        ProdOrderCompCmtLine.FindFirst();
+        Assert.AreEqual(Comment2, ProdOrderCompCmtLine.Comment, 'Comment for Position 2 should match');
+    end;
+
+    local procedure CreateProductionBOMCommentLineWithComment(ProductionBOMLine: Record "Production BOM Line"; CommentText: Text[80])
+    var
+        ProductionBOMCommentLine: Record "Production BOM Comment Line";
+        LineNo: Integer;
+    begin
+        ProductionBOMCommentLine.SetRange("Production BOM No.", ProductionBOMLine."Production BOM No.");
+        ProductionBOMCommentLine.SetRange("Version Code", ProductionBOMLine."Version Code");
+        ProductionBOMCommentLine.SetRange("BOM Line No.", ProductionBOMLine."Line No.");
+        if ProductionBOMCommentLine.FindLast() then;
+        LineNo := ProductionBOMCommentLine."Line No." + 10000;
+
+        ProductionBOMCommentLine.Init();
+        ProductionBOMCommentLine.Validate("Production BOM No.", ProductionBOMLine."Production BOM No.");
+        ProductionBOMCommentLine.Validate("BOM Line No.", ProductionBOMLine."Line No.");
+        ProductionBOMCommentLine.Validate("Version Code", ProductionBOMLine."Version Code");
+        ProductionBOMCommentLine.Validate("Line No.", LineNo);
+        ProductionBOMCommentLine.Validate(Comment, CommentText);
+        ProductionBOMCommentLine.Insert(true);
+    end;
