+    [Test]
+    [Scope('OnPrem')]
+    procedure CalcRegenPlanNoReqLineForItemUsedInMultipleSubassembliesWhenSupplyEqualsDemand()
+    var
+        ParentItem: Record Item;
+        SubAssemblyItem: array[2] of Record Item;
+        ComponentItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        RequisitionLine: Record "Requisition Line";
+    begin
+        // [SCENARIO] For an item consumed in multiple subassemblies, when supply equals demand, calc regen plan should not create requisition lines.
+        // [GIVEN] Create 4 items with Replenishment: Prod Order, Manufacturing Policy: Make-to-Order, Reordering Policy: Lot-for-Lot
+        Initialize();
+
+        // Create the component item (Item3 - lowest level, used in both subassemblies)
+        CreateMakeToOrderLotForLotItem(ComponentItem);
+
+        // Create the two subassembly items (Item2A, Item2B - each uses Item3)
+        CreateMakeToOrderLotForLotItem(SubAssemblyItem[1]);
+        CreateMakeToOrderLotForLotItem(SubAssemblyItem[2]);
+
+        // Create BOM for subassembly items (each contains ComponentItem with qty 1)
+        CreateCertifiedProductionBOMWithItem(ProductionBOMHeader, ComponentItem."Base Unit of Measure", ComponentItem."No.", 1);
+        SubAssemblyItem[1].Validate("Production BOM No.", ProductionBOMHeader."No.");
+        SubAssemblyItem[1].Modify(true);
+
+        Clear(ProductionBOMHeader);
+        CreateCertifiedProductionBOMWithItem(ProductionBOMHeader, ComponentItem."Base Unit of Measure", ComponentItem."No.", 1);
+        SubAssemblyItem[2].Validate("Production BOM No.", ProductionBOMHeader."No.");
+        SubAssemblyItem[2].Modify(true);
+
+        // Create the parent item (Item1) with BOM containing both subassemblies
+        CreateMakeToOrderLotForLotItem(ParentItem);
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, SubAssemblyItem[1]."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, SubAssemblyItem[1]."No.", 1);
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, SubAssemblyItem[2]."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Modify(true);
+
+        // [GIVEN] Create and Refresh Released Production Order for Parent Item with Quantity = 1
+        // This will create demand for Item3 with Qty = 2 (one from each subassembly)
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, ParentItem."No.", 1);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+
+        // [WHEN] Calculate Regenerative Plan for ComponentItem (Item3)
+        LibraryPlanning.CalcRegenPlanForPlanWksh(ComponentItem, WorkDate(), CalcDate('<+1Y>', WorkDate()));
