+    [Test]
+    procedure RolledUpCapacityCostConsistentWithBlankVsNoBOM()
+    var
+        ParentItem: Record Item;
+        CompItem: Record Item;
+        WorkCenter: Record "Work Center";
+        RoutingHeader: Record "Routing Header";
+        RoutingLine: Record "Routing Line";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        EmptyBOMHeader: Record "Production BOM Header";
+        BOMBuffer: Record "BOM Buffer";
+        BOMCostShares: TestPage "BOM Cost Shares";
+        QtyPer: Integer;
+        RolledUpCapacityCostWithNoBOM: Decimal;
+        RolledUpCapacityCostWithBlankBOM: Decimal;
+    begin
+        // [FEATURE] [BOM Cost Share] [Routing]
+        // [SCENARIO] Rolled-up Capacity Cost should be consistent whether component has blank BOM or no BOM at all.
+        // Blank BOM (empty Production BOM assigned) should behave the same as no BOM.
+        Initialize();
+        QtyPer := LibraryRandom.RandIntInRange(3, 5);
+
+        // [GIVEN] Component item "C" with routing that has capacity costs, replenishment = Prod. Order, no Production BOM.
+        LibraryInventory.CreateItem(CompItem);
+        LibraryManufacturing.CreateWorkCenter(WorkCenter);
+        WorkCenter.Validate("Direct Unit Cost", LibraryRandom.RandDecInRange(10, 50, 2));
+        WorkCenter.Modify(true);
+
+        LibraryManufacturing.CreateRoutingHeader(RoutingHeader, RoutingHeader.Type::Serial);
+        LibraryManufacturing.CreateRoutingLine(
+          RoutingHeader, RoutingLine, '', Format(1), RoutingLine.Type::"Work Center", WorkCenter."No.");
+        RoutingLine.Validate("Run Time", LibraryRandom.RandInt(10));
+        RoutingLine.Modify(true);
+        LibraryManufacturing.UpdateRoutingStatus(RoutingHeader, RoutingHeader.Status::Certified);
+
+        CompItem.Validate("Replenishment System", CompItem."Replenishment System"::"Prod. Order");
+        CompItem.Validate("Routing No.", RoutingHeader."No.");
+        CompItem.Validate("Unit Cost", LibraryRandom.RandDecInRange(10, 50, 2));
+        CompItem.Modify(true);
+
+        // [GIVEN] Parent item "P" with Production BOM containing component "C" with Quantity per > 1.
+        LibraryInventory.CreateItem(ParentItem);
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ParentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+          ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, CompItem."No.", QtyPer);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::"Prod. Order");
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Modify(true);
+
+        // [WHEN] Open BOM Cost Shares for "P" with component "C" having NO Production BOM.
+        BOMCostShares.Trap();
+        RunBOMCostSharesPage(ParentItem);
+        BOMCostShares.Expand(true);
+        BOMCostShares.FILTER.SetFilter(Type, Format(BOMBuffer.Type::Item));
+        BOMCostShares.FILTER.SetFilter("No.", CompItem."No.");
+        RolledUpCapacityCostWithNoBOM := BOMCostShares."Rolled-up Capacity Cost".AsDecimal();
+        BOMCostShares.Close();
+
+        // [GIVEN] Create empty (blank) Production BOM and assign to component "C".
+        LibraryManufacturing.CreateProductionBOMHeader(EmptyBOMHeader, CompItem."Base Unit of Measure");
+        LibraryManufacturing.UpdateProductionBOMStatus(EmptyBOMHeader, EmptyBOMHeader.Status::Certified);
+
+        CompItem.Get(CompItem."No.");
+        CompItem.Validate("Production BOM No.", EmptyBOMHeader."No.");
+        CompItem.Modify(true);
+
+        // [WHEN] Open BOM Cost Shares for "P" with component "C" having blank Production BOM.
+        BOMCostShares.Trap();
+        RunBOMCostSharesPage(ParentItem);
+        BOMCostShares.Expand(true);
+        BOMCostShares.FILTER.SetFilter(Type, Format(BOMBuffer.Type::Item));
+        BOMCostShares.FILTER.SetFilter("No.", CompItem."No.");
+        RolledUpCapacityCostWithBlankBOM := BOMCostShares."Rolled-up Capacity Cost".AsDecimal();
+        BOMCostShares.Close();
+
+        // [THEN] Rolled-up Capacity Cost should be the same whether component has blank BOM or no BOM.
+        Assert.AreEqual(
+          RolledUpCapacityCostWithNoBOM, RolledUpCapacityCostWithBlankBOM,
+          'Rolled-up Capacity Cost should be consistent between blank BOM and no BOM.');
+    end;
 }

