+    [Test]
+    [Scope('OnPrem')]
+    procedure OpenJnlUsesCorrectBatchWhenTemplateNameIsSet()
+    var
+        ReqWkshTemplate: Record "Req. Wksh. Template";
+        ReqWkshName: array[2] of Record "Requisition Wksh. Name";
+        RequisitionLine: Record "Requisition Line";
+        ReqJnlManagement: Codeunit ReqJnlManagement;
+        CurrentJnlBatchName: Code[10];
+    begin
+        // [FEATURE] [Planning Worksheet] [Item Availability by Event]
+        // [SCENARIO] When opening Planning Worksheet from Item Availability by Event, the correct batch is opened
+        // instead of the last used batch.
+        Initialize();
+
+        // [GIVEN] Create a planning worksheet template with two batches: "BATCH1" and "BATCH2"
+        CreateReqWkshTemplate(ReqWkshTemplate, PAGE::"Planning Worksheet");
+
+        ReqWkshName[1].Init();
+        ReqWkshName[1]."Worksheet Template Name" := ReqWkshTemplate.Name;
+        ReqWkshName[1].Name := 'BATCH1';
+        ReqWkshName[1].Insert(true);
+
+        ReqWkshName[2].Init();
+        ReqWkshName[2]."Worksheet Template Name" := ReqWkshTemplate.Name;
+        ReqWkshName[2].Name := 'BATCH2';
+        ReqWkshName[2].Insert(true);
+
+        // [GIVEN] Create a requisition line in BATCH1 with template name and batch name set
+        RequisitionLine.Init();
+        RequisitionLine."Worksheet Template Name" := ReqWkshTemplate.Name;
+        RequisitionLine."Journal Batch Name" := ReqWkshName[1].Name;
+        RequisitionLine."Line No." := 10000;
+        RequisitionLine.Insert();
+
+        // [GIVEN] Set CurrentJnlBatchName to BATCH1 (from the requisition line)
+        CurrentJnlBatchName := RequisitionLine."Journal Batch Name";
+
+        // [WHEN] Call OpenJnl with the requisition line that has template name set but no batch filter
+        // This simulates what happens when ShowDocument is called from Item Availability by Event
+        ReqJnlManagement.OpenJnl(CurrentJnlBatchName, RequisitionLine);
+
+        // [THEN] The CurrentJnlBatchName should still be BATCH1 (not overwritten to a different batch)
+        Assert.AreEqual(
+            ReqWkshName[1].Name,
+            CurrentJnlBatchName,
+            'OpenJnl should preserve the correct batch name when template is already set on requisition line');
+
+        // [THEN] The requisition line should be filtered to BATCH1
+        Assert.AreEqual(
+            ReqWkshName[1].Name,
+            RequisitionLine.GetRangeMax("Journal Batch Name"),
+            'Requisition line should be filtered to the correct batch');
+    end;
+
