+    [Test]
+    [HandlerFunctions('JobCreateSalesInvoiceHandler,MessageHandler')]
+    procedure JobTasksWithSameBillingInfoCombinedIntoOneInvoice()
+    var
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        JobPlanningLine: Record "Job Planning Line";
+        JobTasks: array[2] of Record "Job Task";
+        Customer: Record Customer;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        JobCreateSalesInvoice: Report "Job Create Sales Invoice";
+        Qty: Decimal;
+        OneInvoiceIsCreatedMsg: Label '1 invoice is created.';
+    begin
+        // [SCENARIO] Job Tasks with same SellTo, BillTo, and Invoice Currency Code are combined into one invoice
+        // when using Job Create Sales Invoice report with Multiple Customers Billing Method
+        Initialize();
+
+        // [GIVEN] Set Multiple Customers on Project Setup
+        SetMultiupleCustomersOnProjectSetup();
+
+        // [GIVEN] Create Customer
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] Create new Project with the Customer
+        LibraryJob.CreateJob(Job, Customer."No.");
+
+        // [GIVEN] Create Project Task 1 with Customer (SellTo = Customer, BillTo = Customer)
+        LibraryJob.CreateJobTask(Job, JobTasks[1]);
+
+        // [GIVEN] Create Project Task 2 with same Customer (SellTo = Customer, BillTo = Customer)
+        LibraryJob.CreateJobTask(Job, JobTasks[2]);
+
+        // [GIVEN] Create Job Planning Lines with Qty to Transfer to Invoice for both tasks
+        Qty := LibraryRandom.RandInt(10);
+        CreateJobPlanningLineWithQtyToTransferToInvoice(JobPlanningLine, JobTasks[1], Qty, Qty);
+        CreateJobPlanningLineWithQtyToTransferToInvoice(JobPlanningLine, JobTasks[2], Qty, Qty);
+
+        // [GIVEN] Enqueue expected message - 1 invoice should be created since both tasks have same billing info
+        LibraryVariableStorage.Enqueue(OneInvoiceIsCreatedMsg);
+
+        // [WHEN] Run batch job "Create Job Sales Invoice" for Job Tasks
+        Commit();
+        JobTask.SetFilter("Job No.", '%1', Job."No.");
+        JobCreateSalesInvoice.SetTableView(JobTask);
+        JobCreateSalesInvoice.Run();
+
+        // [THEN] Verify only 1 Sales Invoice is created
+        SalesHeader.SetRange("Document Type", SalesHeader."Document Type"::Invoice);
+        SalesHeader.SetRange("Sell-to Customer No.", Customer."No.");
+        SalesHeader.SetRange("Bill-to Customer No.", Customer."No.");
+        Assert.RecordCount(SalesHeader, 1);
+
+        // [THEN] Verify the invoice has 2 sales lines (one for each job task)
+        SalesHeader.FindFirst();
+        SalesLine.SetRange("Document Type", SalesHeader."Document Type");
+        SalesLine.SetRange("Document No.", SalesHeader."No.");
+        SalesLine.SetRange("Job No.", Job."No.");
+        Assert.RecordCount(SalesLine, 2);
+    end;
