+    [Test]
+    [HandlerFunctions('ItemTrackingLinesLotAssignPageHandler')]
+    [Scope('OnPrem')]
+    procedure RecalcPlanWithPlanningFlexNoneDoesNotCreateDuplicateSurplusReservEntries()
+    var
+        Item: Record Item;
+        ItemTrackingCode: Record "Item Tracking Code";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        PurchaseLine: Record "Purchase Line";
+        RequisitionLine: Record "Requisition Line";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+        ReservationEntry: Record "Reservation Entry";
+        LibraryItemTracking: Codeunit "Library - Item Tracking";
+        OriginalQuantity: Decimal;
+        IncreasedQuantity: Decimal;
+        SurplusQuantity: Decimal;
+    begin
+        // [FEATURE] [Planning] [Item Tracking] [Reservation]
+        // [SCENARIO 567421] When recalculating a requisition/planning worksheet for an item with no planning results,
+        // surplus entries in the reservation table should not be duplicated on the purchase line's item tracking.
+
+        // [GIVEN] Create an Item with Lot-for-Lot reordering policy and lot tracking enabled.
+        Initialize();
+        LibraryItemTracking.CreateItemTrackingCode(ItemTrackingCode, false, true);  // Lot Specific Tracking = TRUE
+        CreateItem(Item, Item."Reordering Policy"::"Lot-for-Lot", Item."Replenishment System"::Purchase);
+        Item.Validate("Item Tracking Code", ItemTrackingCode.Code);
+        Item.Validate("Lot Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        Item.Modify(true);
+
+        // [GIVEN] Create a Sales Order for the item.
+        OriginalQuantity := LibraryRandom.RandIntInRange(50, 100);
+        IncreasedQuantity := OriginalQuantity + LibraryRandom.RandIntInRange(20, 50);
+        SurplusQuantity := IncreasedQuantity - OriginalQuantity;
+        CreateSalesOrder(SalesHeader, SalesLine, Item."No.", OriginalQuantity);
+
+        // [GIVEN] Calculate Plan in Requisition Worksheet to meet the demand.
+        CalculatePlanForRequisitionWorksheet(RequisitionWkshName, Item, WorkDate(), CalcDate('<+30D>', WorkDate()));
+
+        // [GIVEN] Increase the quantity on the requisition line and set Planning Flexibility to None.
+        SelectRequisitionLine(RequisitionLine, Item."No.");
+        RequisitionLine.Validate(Quantity, IncreasedQuantity);
+        RequisitionLine.Validate("Planning Flexibility", RequisitionLine."Planning Flexibility"::None);
+        RequisitionLine.Validate("Vendor No.", LibraryPurchase.CreateVendorNo());
+        RequisitionLine.Modify(true);
+
+        // [GIVEN] Assign Lot No. tracking on the requisition line.
+        RequisitionLine.OpenItemTrackingLines();
+
+        // [GIVEN] Carry out Action Message to create a Purchase Order.
+        AcceptActionMessage(Item."No.");
+        SelectRequisitionLine(RequisitionLine, Item."No.");
+        LibraryPlanning.CarryOutReqWksh(RequisitionLine, WorkDate(), WorkDate(), WorkDate(), WorkDate(), '');
+
+        // [GIVEN] Verify purchase order was created with the increased quantity.
+        SelectPurchaseLine(PurchaseLine, Item."No.");
+        Assert.AreEqual(IncreasedQuantity, PurchaseLine.Quantity, 'Purchase Line Quantity should be the increased amount');
+
+        // [GIVEN] Count reservation entries with status Surplus on the purchase line before recalc.
+        ReservationEntry.SetRange("Source Type", Database::"Purchase Line");
+        ReservationEntry.SetRange("Source ID", PurchaseLine."Document No.");
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Surplus);
+        Assert.AreEqual(1, ReservationEntry.Count(), 'Should have exactly one Surplus reservation entry before recalc');
+
+        // [WHEN] Recalculate the plan (which should result in no new planning lines due to Planning Flexibility = None).
+        RequisitionWkshName.FindFirst();
+        LibraryPlanning.CalculatePlanForReqWksh(
+            Item, RequisitionWkshName."Worksheet Template Name", RequisitionWkshName.Name, WorkDate(), CalcDate('<+30D>', WorkDate()));
+
+        // [THEN] No new requisition lines should be created.
+        FilterOnRequisitionLine(RequisitionLine, Item."No.");
+        Assert.IsTrue(RequisitionLine.IsEmpty(), StrSubstNo(RequisitionLineMustNotExistTxt, Item."No."));
+
+        // [THEN] The reservation entries on the purchase line should NOT be duplicated.
+        // Before the fix, the surplus entry quantity was duplicated each time the plan was recalculated.
+        ReservationEntry.Reset();
+        ReservationEntry.SetRange("Source Type", Database::"Purchase Line");
+        ReservationEntry.SetRange("Source ID", PurchaseLine."Document No.");
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Surplus);
+        Assert.AreEqual(1, ReservationEntry.Count(), 'Should still have exactly one Surplus reservation entry after recalc');
+        ReservationEntry.FindFirst();
+        Assert.AreEqual(SurplusQuantity, ReservationEntry."Quantity (Base)", 'Surplus quantity should be unchanged after recalc');
+    end;
+
