+        PurchaseOrderNo: Code[20];
+        OriginalPurchaseQuantity: Decimal;
+        SalesQuantity: Decimal;
+    begin
+        // [SCENARIO] When filtering Planning Worksheet by Action Message (e.g. Cancel) and running Carry Out Action Message,
+        // only the filtered lines should be processed, not all lines with Accept Action Message = true.
+        // [GIVEN] An item with Order reordering policy
+        Initialize();
+        CreateItem(Item, Item."Reordering Policy"::Order, Item."Replenishment System"::Purchase);
+
+        // [GIVEN] A purchase order for the item with a past date (will generate Cancel action message)
+        OriginalPurchaseQuantity := LibraryRandom.RandIntInRange(5, 10);
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Order, Item."Vendor No.");
+        LibraryPurchase.CreatePurchaseLine(PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item, Item."No.", OriginalPurchaseQuantity);
+        PurchaseLine.Validate("Expected Receipt Date", CalcDate('<-1M>', WorkDate()));
+        PurchaseLine.Modify(true);
+        PurchaseOrderNo := PurchaseHeader."No.";
+
+        // [GIVEN] A sales order for the item with a future date (will generate New action message for a new purchase)
+        SalesQuantity := LibraryRandom.RandIntInRange(1, 4);
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, '');
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", SalesQuantity);
+        SalesLine.Validate("Shipment Date", CalcDate('<+1M>', WorkDate()));
+        SalesLine.Modify(true);
+
+        // [GIVEN] Calculate regenerative plan to generate requisition lines
+        Item.SetRecFilter();
+        LibraryPlanning.CalcRegenPlanForPlanWksh(Item, CalcDate('<-2M>', WorkDate()), CalcDate('<+2M>', WorkDate()));
+
+        // [GIVEN] Verify we have both Cancel and New action messages
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        Assert.IsTrue(RequisitionLine.FindFirst(), 'Expected Cancel action message line');
+        RequisitionLine.Validate("Accept Action Message", true);
+        RequisitionLine.Modify(true);
+
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::New);
+        Assert.IsTrue(RequisitionLine.FindFirst(), 'Expected New action message line');
+        RequisitionLine.Validate("Accept Action Message", true);
+        RequisitionLine.Modify(true);
+
+        // [WHEN] Filter by Action Message = Cancel and run Carry Out Action Message
+        RequisitionLine.Reset();
+        RequisitionLine.SetRange("Worksheet Template Name", RequisitionLine."Worksheet Template Name");
+        RequisitionLine.SetRange("Journal Batch Name", RequisitionLine."Journal Batch Name");
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        RequisitionLine.FindFirst();
+        Commit();
+
+        CarryOutActionMsgPlan.SetReqWkshLine(RequisitionLine);
+        CarryOutActionMsgPlan.InitializeRequest(0, 1, 0, 0); // Make Purch. Orders
+        CarryOutActionMsgPlan.SetTableView(RequisitionLine);
+        CarryOutActionMsgPlan.UseRequestPage(false);
+        CarryOutActionMsgPlan.RunModal();
+
+        // [THEN] The Cancel line should have been processed (original purchase order cancelled)
+        PurchaseHeader.SetRange("No.", PurchaseOrderNo);
+        Assert.IsTrue(PurchaseHeader.IsEmpty(), 'The original Purchase Order should have been cancelled');
+
+        // [THEN] The New line should NOT have been processed (still exists in planning worksheet)
+        RequisitionLine.Reset();
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::New);
+        Assert.IsTrue(RequisitionLine.FindFirst(), 'The New action message line should still exist because it was filtered out');
+    end;
